INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_cafe_C1_01', 'place', 'an order', 'place an order', '주문을 넣다', 'make', '''place an order''는 격식 있는 표현으로, 식당이나 카페에서 직원에게 정중하게 주문할 때 자주 써요. ''make an order''보다 더 자연스러워요.', 'Would you like to place an order, sir?', '주문하시겠어요, 손님?', 'I''d like to place an order for delivery, please.', '배달 주문을 넣고 싶어요.', 'C1', 'cafe', 2, 'restaurant order menu'),
('col_cafe_C1_02', 'split', 'the bill', 'split the bill', '계산을 나누다', 'divide', '친구나 동료와 식사 후 더치페이할 때 쓰는 표준 표현이에요. ''divide''보다 ''split''이 훨씬 자연스럽게 들려요.', 'Shall we split the bill evenly?', '계산을 똑같이 나눌까요?', 'Let''s split the bill three ways.', '셋이서 나눠서 계산해요.', 'C1', 'cafe', 2, 'restaurant bill payment'),
('col_cafe_C1_03', 'settle', 'the tab', 'settle the tab', '계산을 정산하다', 'pay', '바나 카페에서 미리 주문한 음료/음식 값을 마지막에 한꺼번에 정산할 때 써요. 격식 있고 세련된 표현이에요.', 'I''ll settle the tab on my way out.', '나갈 때 정산할게요.', 'He kindly offered to settle the tab for everyone.', '그가 친절하게 모두의 계산을 해주겠다고 했어요.', 'C1', 'cafe', 2, 'bar tab payment'),
('col_cafe_C1_04', 'savor', 'the moment', 'savor the moment', '순간을 음미하다', 'enjoy', '단순히 즐기는 것을 넘어, 천천히 깊이 음미한다는 뉘앙스예요. 카페에서 여유롭게 시간을 보낼 때 어울려요.', 'She closed her eyes to savor the moment.', '그녀는 그 순간을 음미하려 눈을 감았어요.', 'I love to savor the moment with a quiet espresso.', '조용히 에스프레소 한 잔과 그 순간을 음미하는 걸 좋아해요.', 'C1', 'cafe', 2, 'coffee moment relax'),
('col_cafe_C1_05', 'linger', 'over coffee', 'linger over coffee', '커피를 마시며 오래 머물다', 'stay', '커피 한 잔을 두고 오래 앉아 대화하거나 시간을 보낸다는 우아한 표현이에요. 카페 문화를 묘사할 때 자주 등장해요.', 'We lingered over coffee for hours.', '우린 커피를 마시며 몇 시간이나 머물렀어요.', 'Parisians love to linger over coffee in the afternoon.', '파리지앵들은 오후에 커피를 천천히 즐기는 걸 좋아해요.', 'C1', 'cafe', 2, 'paris cafe coffee')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_cafe_C1_01', 'grab a bite', '간단히 한 끼 먹다', '한 입 잡다', '바쁜 일정 사이에 가볍게 식사할 때 쓰는 캐주얼한 표현이에요. 동료나 친구에게 점심 제안할 때 자연스러워요.', 'Want to grab a bite before the meeting?', '회의 전에 뭐 좀 먹을래요?', 'I only had time to grab a bite at the airport.', '공항에서 간단히 먹을 시간밖에 없었어요.', NULL, NULL, 'C1', 'cafe', 2, 'quick lunch sandwich', 1),
('idm_cafe_C1_02', 'my treat', '내가 살게', '내 대접', '식사나 커피값을 내가 내겠다고 친근하게 말할 때 쓰는 표현이에요. 격식 자리보다 친한 사이에 더 어울려요.', 'Order whatever you like — my treat!', '먹고 싶은 거 뭐든 시켜요 — 제가 살게요!', 'Lunch is on me today; it''s my treat.', '오늘 점심은 제가 살게요.', NULL, NULL, 'C1', 'cafe', 2, 'paying restaurant friend', 2),
('idm_cafe_C1_03', 'on the house', '가게에서 서비스로 주는', '집(가게) 위에', '식당이나 바에서 무료로 제공하는 음식/음료를 말해요. 단골이거나 특별한 상황에서 자주 듣게 돼요.', 'The dessert is on the house tonight.', '오늘 디저트는 서비스예요.', 'The chef sent over a glass of wine on the house.', '셰프가 와인 한 잔을 서비스로 보내줬어요.', NULL, NULL, 'C1', 'cafe', 2, 'complimentary wine glass', 3),
('idm_cafe_C1_04', 'a hole in the wall', '작지만 매력 있는 가게', '벽에 난 구멍', '작고 눈에 잘 안 띄지만 음식이 맛있는 숨은 맛집을 가리켜요. 부정적이지 않고 오히려 칭찬에 가까운 표현이에요.', 'It''s a real hole in the wall, but the noodles are incredible.', '진짜 허름한 가게인데 국수가 끝내줘요.', 'We found this lovely hole in the wall in a side alley.', '골목길에서 작고 멋진 숨은 가게를 발견했어요.', NULL, NULL, 'C1', 'cafe', 2, 'tiny restaurant alley', 4),
('idm_cafe_C1_05', 'for here or to go', '드시고 가세요 아니면 포장이세요', '여기에서 또는 가져가기', '카페·패스트푸드에서 직원이 거의 항상 묻는 표현이에요. ''eat in or take away''(영국식)와 같은 뜻이에요.', 'Is that for here or to go?', '드시고 가세요, 아니면 포장이세요?', 'Two lattes to go, please.', '라테 두 잔 포장해 주세요.', NULL, NULL, 'C1', 'cafe', 2, 'takeaway coffee cup', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_work_C1_01', 'meet', 'a deadline', 'meet a deadline', '마감을 지키다', 'keep', '직장에서 가장 자주 쓰이는 콜로케이션 중 하나예요. ''keep a deadline''은 어색하고 반드시 ''meet''을 써야 해요.', 'We''re struggling to meet the deadline.', '마감을 맞추느라 고전하고 있어요.', 'She always meets her deadlines, no matter what.', '그녀는 무슨 일이 있어도 늘 마감을 지켜요.', 'C1', 'work', 2, 'deadline calendar work'),
('col_work_C1_02', 'delegate', 'tasks', 'delegate tasks', '업무를 위임하다', 'give', '관리자가 부하 직원에게 일을 맡기는 격식 있는 표현이에요. ''give tasks''보다 훨씬 전문적으로 들려요.', 'Good managers know how to delegate tasks effectively.', '훌륭한 관리자는 업무를 효과적으로 위임할 줄 알아요.', 'I need to delegate more tasks to focus on strategy.', '전략에 집중하려면 업무를 더 많이 위임해야 해요.', 'C1', 'work', 2, 'manager delegating team'),
('col_work_C1_03', 'step', 'up', 'step up', '책임지고 나서다', 'stand', '필요할 때 자발적으로 더 큰 역할이나 책임을 맡는다는 뜻이에요. 리더십 맥락에서 자주 들려요.', 'When the manager left, she stepped up immediately.', '매니저가 떠나자 그녀가 바로 나섰어요.', 'We need someone to step up and lead the project.', '나서서 프로젝트를 이끌 사람이 필요해요.', 'C1', 'work', 2, 'leadership team meeting'),
('col_work_C1_04', 'weigh', 'in', 'weigh in on', '의견을 제시하다', 'say', '논의나 결정에 본인의 의견을 보태는 격식 있는 표현이에요. 회의에서 ''Could you weigh in on this?''처럼 자주 써요.', 'Would you like to weigh in on the proposal?', '이 제안에 의견 주실래요?', 'Several experts weighed in on the debate.', '여러 전문가가 그 논쟁에 의견을 보탰어요.', 'C1', 'work', 2, 'meeting discussion opinion'),
('col_work_C1_05', 'follow', 'through', 'follow through', '끝까지 해내다', 'finish', '시작한 일을 끝까지 책임지고 완수한다는 뜻이에요. 약속이나 계획을 지키는 신뢰성을 강조할 때 써요.', 'He always follows through on his commitments.', '그는 늘 약속을 끝까지 지켜요.', 'Talking is easy, but you have to follow through.', '말은 쉬워요, 끝까지 해내는 게 중요해요.', 'C1', 'work', 2, 'project completion checklist')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_work_C1_01', 'burn the midnight oil', '밤늦게까지 일하다', '한밤중의 기름을 태우다', '예전에 기름 램프로 밤늦게 일하던 것에서 유래한 표현이에요. 야근이나 시험공부를 묘사할 때 어울려요.', 'I''ve been burning the midnight oil to finish the report.', '보고서 끝내려고 밤늦게까지 일하고 있어요.', 'She burned the midnight oil all week before the launch.', '출시 전 일주일 내내 밤샘 작업했어요.', NULL, NULL, 'C1', 'work', 2, 'office late night work', 1),
('idm_work_C1_02', 'go the extra mile', '한 발 더 노력하다', '추가로 1마일을 가다', '기대 이상으로 노력하거나 헌신할 때 쓰는 칭찬 표현이에요. 평가나 추천서에 자주 등장해요.', 'She always goes the extra mile for her clients.', '그녀는 늘 고객을 위해 한 발 더 노력해요.', 'Going the extra mile makes all the difference.', '한 발 더 가는 노력이 큰 차이를 만들어요.', NULL, NULL, 'C1', 'work', 2, 'employee dedication effort', 2),
('idm_work_C1_03', 'in the loop', '진행 상황을 공유받는', '고리(루프) 안에', '정보 공유 대상에 포함되어 있다는 뜻이에요. 비즈니스 이메일에서 ''Please keep me in the loop''로 자주 써요.', 'Please keep me in the loop on any updates.', '업데이트 있으면 저한테도 공유 부탁드려요.', 'Make sure HR is in the loop before you announce it.', '발표 전에 인사팀에 꼭 공유하세요.', NULL, NULL, 'C1', 'work', 2, 'email communication team', 3),
('idm_work_C1_04', 'back to square one', '원점으로 돌아가다', '1번 칸으로 돌아가기', '진행하던 일이 무산되어 처음부터 다시 시작해야 할 때 써요. 보드게임에서 유래한 표현이에요.', 'The client rejected our proposal — back to square one.', '고객이 제안을 거절했어요 — 원점이네요.', 'After the merger fell through, we were back to square one.', '합병이 무산된 뒤 다시 처음으로 돌아갔어요.', NULL, NULL, 'C1', 'work', 2, 'restart frustration project', 4),
('idm_work_C1_05', 'wear many hats', '여러 역할을 동시에 하다', '많은 모자를 쓰다', '한 사람이 여러 직책이나 업무를 동시에 수행할 때 써요. 특히 스타트업이나 중소기업 환경에서 자주 들려요.', 'In a startup, you have to wear many hats.', '스타트업에서는 여러 역할을 동시에 해야 해요.', 'As a freelancer, I wear many hats every day.', '프리랜서로서 매일 여러 역할을 해요.', NULL, NULL, 'C1', 'work', 2, 'startup multitasking roles', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_travel_C1_01', 'book', 'accommodations', 'book accommodations', '숙소를 예약하다', 'reserve', '''book''이 영어권에서 훨씬 자연스러워요. ''accommodations''(미국식 복수)는 호텔·숙박 시설을 포괄하는 격식 단어예요.', 'Have you booked your accommodations yet?', '숙소 예약은 하셨어요?', 'I always book my accommodations months in advance.', '저는 늘 몇 달 전에 숙소를 예약해요.', 'C1', 'travel', 2, 'hotel booking laptop'),
('col_travel_C1_02', 'settle', 'into a routine', 'settle into a routine', '일상에 적응하다', 'enter', '새로운 환경에 점차 익숙해져 안정된 패턴을 만든다는 뜻이에요. 장기 여행이나 이주 후의 적응 과정을 표현할 때 어울려요.', 'It took a week to settle into a routine abroad.', '해외 일상에 적응하는 데 일주일 걸렸어요.', 'Once you settle into a routine, travel feels easier.', '일상이 자리 잡히면 여행이 더 수월해져요.', 'C1', 'travel', 2, 'morning routine abroad'),
('col_travel_C1_03', 'wander', 'aimlessly', 'wander aimlessly', '정처 없이 거닐다', 'walk', '뚜렷한 목적지 없이 자유롭게 돌아다닌다는 낭만적인 뉘앙스가 있어요. 여행 에세이나 일기에 자주 등장해요.', 'I love to wander aimlessly through old towns.', '오래된 도시를 정처 없이 거니는 걸 좋아해요.', 'We wandered aimlessly until we found a hidden plaza.', '숨겨진 광장을 발견할 때까지 정처 없이 걸었어요.', 'C1', 'travel', 2, 'old town wander walking'),
('col_travel_C1_04', 'absorb', 'the culture', 'absorb the culture', '문화를 흡수하다', 'learn', '단순히 보거나 배우는 게 아니라 깊이 체험하고 받아들인다는 의미예요. 문화 여행이나 어학연수 설명에 잘 어울려요.', 'Living there really lets you absorb the culture.', '거기 살면 문화를 제대로 흡수하게 돼요.', 'She traveled slowly to absorb the local culture.', '그녀는 현지 문화를 체득하려 천천히 여행했어요.', 'C1', 'travel', 2, 'local market culture'),
('col_travel_C1_05', 'soak', 'up the atmosphere', 'soak up the atmosphere', '분위기를 만끽하다', 'feel', '한 장소의 분위기와 정취를 천천히 즐긴다는 표현이에요. 카페, 광장, 축제 같은 장소 묘사에 자주 써요.', 'We just sat there and soaked up the atmosphere.', '그냥 거기 앉아 분위기를 만끽했어요.', 'I soaked up the atmosphere of the night market.', '야시장의 분위기를 흠뻑 즐겼어요.', 'C1', 'travel', 2, 'night market atmosphere')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_travel_C1_01', 'off the beaten path', '잘 알려지지 않은 곳에', '다져진 길에서 벗어난', '관광객이 잘 가지 않는 숨은 장소를 묘사할 때 써요. 여행 블로그나 가이드북에 단골로 등장하는 표현이에요.', 'We love restaurants that are off the beaten path.', '저희는 잘 알려지지 않은 식당을 좋아해요.', 'This village is truly off the beaten path.', '이 마을은 정말 잘 알려지지 않은 곳이에요.', NULL, NULL, 'C1', 'travel', 2, 'hidden village mountain', 1),
('idm_travel_C1_02', 'live out of a suitcase', '여행지를 떠돌며 지내다', '여행 가방에서 살다', '짐을 풀지 못한 채 여기저기 옮겨 다니며 사는 생활을 의미해요. 출장이 잦은 사람이나 장기 여행자가 자주 써요.', 'I''ve been living out of a suitcase for months.', '몇 달째 가방 들고 떠돌고 있어요.', 'Frequent business travelers live out of a suitcase.', '출장이 잦은 사람들은 가방 들고 사는 셈이죠.', NULL, NULL, 'C1', 'travel', 2, 'suitcase hotel room', 2),
('idm_travel_C1_03', 'the road less traveled', '남들이 가지 않는 길', '덜 다녀진 길', '로버트 프로스트의 시에서 유래한 표현으로, 남들과 다른 선택이나 여정을 의미해요. 다소 시적이고 격조 있는 어조예요.', 'She chose the road less traveled and moved to Iceland.', '그녀는 남들이 안 가는 길을 택해 아이슬란드로 갔어요.', 'Sometimes the road less traveled is the most rewarding.', '때로는 덜 가본 길이 가장 보람 있어요.', NULL, NULL, 'C1', 'travel', 2, 'lonely forest path', 3),
('idm_travel_C1_04', 'catch a flight', '비행기를 잡다', '비행기를 잡다', '비행기를 시간 안에 타다는 표현이에요. ''miss a flight''(놓치다)의 반대로, 일상적으로 자주 써요.', 'I need to catch a flight at 6 a.m.', '아침 6시 비행기를 타야 해요.', 'We barely caught our connecting flight.', '환승 비행기를 간신히 잡았어요.', NULL, NULL, 'C1', 'travel', 2, 'airport boarding gate', 4),
('idm_travel_C1_05', 'in transit', '이동 중인', '운송 중인', '한 장소에서 다른 장소로 이동 중이라는 격식 있는 표현이에요. 공항 환승 구역이나 우편물 추적에도 흔히 보여요.', 'Your package is currently in transit.', '소포가 현재 이동 중이에요.', 'I''ll be in transit between flights all day.', '하루 종일 환승 중일 거예요.', NULL, NULL, 'C1', 'travel', 2, 'transit airport passenger', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_home_C1_01', 'settle', 'in', 'settle in', '새 집에 자리 잡다', 'enter', '이사 후 새로운 공간에 익숙해지고 짐을 정리하며 안정되는 과정을 표현해요. 이사 인사나 안부에서 자주 들려요.', 'Have you settled in yet?', '이사 잘 적응하셨어요?', 'It takes about a month to fully settle in.', '완전히 자리 잡는 데 한 달 정도 걸려요.', 'C1', 'home', 2, 'new apartment unpacking'),
('col_home_C1_02', 'do', 'up a place', 'do up a place', '집을 꾸미다·수리하다', 'decorate', '낡은 집을 보수하거나 새 집을 멋지게 꾸미는 것을 영국식으로 표현해요. 인테리어 잡지에서 자주 등장해요.', 'They did up the cottage beautifully.', '그들은 그 별장을 멋지게 꾸몄어요.', 'We''re doing up the kitchen next month.', '다음 달에 부엌을 리모델링할 거예요.', 'C1', 'home', 2, 'kitchen renovation home'),
('col_home_C1_03', 'share', 'a flat', 'share a flat', '집을 함께 쓰다', 'live', '주로 영국식 표현으로, 한 아파트를 룸메이트와 공유한다는 뜻이에요. 미국식은 ''share an apartment''예요.', 'I shared a flat with two friends in London.', '런던에서 친구 둘과 집을 함께 썼어요.', 'Sharing a flat helps cut down on rent.', '집을 함께 쓰면 월세를 줄일 수 있어요.', 'C1', 'home', 2, 'roommates flat london'),
('col_home_C1_04', 'set', 'up home', 'set up home', '살림을 차리다', 'make', '결혼이나 이주 후 새 보금자리를 마련한다는 뜻으로, 다소 격식 있고 따뜻한 뉘앙스예요.', 'They set up home in a quiet coastal town.', '그들은 조용한 해안 도시에 살림을 차렸어요.', 'After marriage, they set up home in Seoul.', '결혼 후 그들은 서울에 보금자리를 마련했어요.', 'C1', 'home', 2, 'coastal town house'),
('col_home_C1_05', 'feel', 'at home', 'feel at home', '편안하다·내 집 같다', 'be', '낯선 장소나 상황에서 편안함을 느낀다는 따뜻한 표현이에요. 손님맞이 인사에 자주 써요.', 'Please make yourself comfortable — feel at home.', '편하게 계세요 — 내 집처럼요.', 'I felt at home from the moment I arrived.', '도착한 순간부터 편안했어요.', 'C1', 'home', 2, 'cozy living room')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_home_C1_01', 'make yourself at home', '편하게 계세요', '스스로를 집에 있게 하다', '손님이 왔을 때 격식 없이 편하게 지내라고 권하는 따뜻한 표현이에요. 호스트가 거의 반드시 쓰는 인사말이에요.', 'Come in, make yourself at home!', '들어오세요, 편히 계세요!', 'He told us to make ourselves at home while he cooked.', '그가 요리하는 동안 편히 있으라고 했어요.', NULL, NULL, 'C1', 'home', 2, 'guest welcoming sofa', 1),
('idm_home_C1_02', 'home sweet home', '내 집이 최고', '집, 달콤한 집', '여행이나 외출 후 집에 돌아왔을 때의 안도감을 표현해요. 진심 어린 감탄이나 가벼운 농담으로 모두 쓸 수 있어요.', 'Finally back — home sweet home!', '드디어 돌아왔다 — 역시 내 집이 최고!', 'After a long trip, nothing beats home sweet home.', '긴 여행 끝에 내 집만 한 곳이 없어요.', NULL, NULL, 'C1', 'home', 2, 'cozy bedroom returning', 2),
('idm_home_C1_03', 'under one roof', '한 지붕 아래에', '하나의 지붕 아래', '여러 사람이 한 집에 함께 산다는 뜻으로, 대가족이나 셰어하우스를 묘사할 때 자주 써요.', 'Three generations live under one roof.', '삼대가 한 지붕 아래 살아요.', 'It''s rare to have so many cousins under one roof.', '사촌이 이렇게 많이 한집에 사는 건 드물어요.', NULL, NULL, 'C1', 'home', 2, 'large family house', 3),
('idm_home_C1_04', 'right at home', '아주 편안한', '곧바로 집처럼', '어떤 장소나 상황이 마치 내 집인 듯 자연스럽고 편안하다는 강조 표현이에요. ''feel at home''보다 더 강한 어감이에요.', 'She felt right at home with the team.', '그녀는 그 팀과 곧바로 편안함을 느꼈어요.', 'You''ll feel right at home in this neighborhood.', '이 동네에서 금방 편안해질 거예요.', NULL, NULL, 'C1', 'home', 2, 'neighborhood community comfort', 4),
('idm_home_C1_05', 'a roof over your head', '머물 곳·살 곳', '머리 위의 지붕', '거창하지 않아도 살 집이 있다는 것을 강조할 때 써요. 감사함이나 기본적인 안정을 이야기할 때 자주 등장해요.', 'At least we have a roof over our heads.', '적어도 살 집은 있잖아요.', 'Be grateful for a roof over your head.', '살 곳이 있다는 것에 감사하세요.', NULL, NULL, 'C1', 'home', 2, 'simple house shelter', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_shopping_C1_01', 'browse', 'the shelves', 'browse the shelves', '진열대를 둘러보다', 'look', '특정 상품을 정하지 않고 천천히 진열대를 구경한다는 뜻이에요. 서점이나 마트 묘사에 자주 어울려요.', 'I love browsing the shelves at the bookstore.', '서점에서 책장 둘러보는 걸 좋아해요.', 'She spent an hour browsing the shelves.', '그녀는 한 시간 동안 진열대를 둘러봤어요.', 'C1', 'shopping', 2, 'bookstore shelves browsing'),
('col_shopping_C1_02', 'snap', 'up a bargain', 'snap up a bargain', '특가 상품을 잽싸게 사다', 'get', '좋은 물건이 매진되기 전 재빨리 낚아챈다는 활기찬 표현이에요. 세일이나 한정 판매 맥락에 잘 어울려요.', 'Shoppers snapped up the bargains within minutes.', '쇼핑객들이 몇 분 만에 특가 상품을 다 채갔어요.', 'I snapped up a bargain on a winter coat.', '겨울 코트를 특가로 잽싸게 샀어요.', 'C1', 'shopping', 2, 'sale rush shoppers'),
('col_shopping_C1_03', 'compare', 'prices', 'compare prices', '가격을 비교하다', 'check', '구매 전 여러 가게나 사이트의 가격을 따져본다는 기본적인 쇼핑 표현이에요. 온라인 쇼핑 맥락에서 더 자주 들려요.', 'I always compare prices before I buy.', '저는 늘 사기 전에 가격을 비교해요.', 'You can compare prices across multiple sites.', '여러 사이트에서 가격을 비교할 수 있어요.', 'C1', 'shopping', 2, 'price comparison online'),
('col_shopping_C1_04', 'splash', 'out on', 'splash out on', '큰돈을 쓰다', 'spend', '평소보다 큰돈을 흔쾌히 쓴다는 뉘앙스로, 약간의 사치를 즐기는 어감이에요. 영국식에서 더 자주 들려요.', 'They splashed out on a designer handbag.', '그들은 명품 가방에 큰돈을 썼어요.', 'I splashed out on a nice dinner last night.', '어젯밤 멋진 저녁에 꽤 돈을 썼어요.', 'C1', 'shopping', 2, 'luxury handbag boutique'),
('col_shopping_C1_05', 'stick', 'to a budget', 'stick to a budget', '예산을 지키다', 'keep', '미리 정한 예산 범위 안에서 쇼핑한다는 책임 있는 표현이에요. 가계부나 재테크 맥락에 자주 등장해요.', 'It''s hard to stick to a budget during the holidays.', '연말엔 예산을 지키기가 어려워요.', 'She always sticks to her shopping budget.', '그녀는 늘 쇼핑 예산을 지켜요.', 'C1', 'shopping', 2, 'budget planner wallet')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_shopping_C1_01', 'shop around', '여러 곳을 비교해서 사다', '돌아다니며 쇼핑하다', '한 곳에서 바로 사지 않고 여러 가게나 사이트를 비교해 본다는 뜻이에요. 똑똑한 소비자의 행동을 묘사할 때 자주 써요.', 'Shop around before committing to a purchase.', '사기 전에 여러 곳을 비교해 보세요.', 'I shopped around for the best insurance deal.', '가장 좋은 보험 상품을 찾아 비교해 봤어요.', NULL, NULL, 'C1', 'shopping', 2, 'comparing shops customer', 1),
('idm_shopping_C1_02', 'a steal', '거저나 다름없는 가격', '훔친 것', '가격에 비해 정말 가치 있는 좋은 거래를 표현해요. ''bargain''보다 더 강한 어감이에요.', 'At that price, it''s an absolute steal.', '그 가격이면 거저예요.', 'The vintage jacket was a real steal.', '그 빈티지 자켓은 정말 거저였어요.', NULL, NULL, 'C1', 'shopping', 2, 'vintage jacket sale', 2),
('idm_shopping_C1_03', 'window shopping', '아이쇼핑', '창문 쇼핑', '실제로 사지 않고 구경만 한다는 뜻이에요. 한국어 ''아이쇼핑''과 비슷하지만 ''eye shopping''은 콩글리시예요.', 'I went window shopping all afternoon.', '오후 내내 아이쇼핑 했어요.', 'Window shopping is my favorite weekend activity.', '아이쇼핑이 제일 좋아하는 주말 활동이에요.', NULL, NULL, 'C1', 'shopping', 2, 'shop window display', 3),
('idm_shopping_C1_04', 'break the bank', '돈을 거덜내다', '은행을 부수다', '큰돈을 써서 재정에 부담이 된다는 뜻이에요. 부정문(''won''t break the bank'')으로 ''비싸지 않다''는 뜻으로도 자주 써요.', 'A nice meal out won''t break the bank.', '괜찮은 외식 한 번으론 거덜 나지 않아요.', 'That handbag would totally break the bank.', '그 가방은 완전히 거덜 낼 거예요.', NULL, NULL, 'C1', 'shopping', 2, 'empty wallet expensive', 4),
('idm_shopping_C1_05', 'drive a hard bargain', '깐깐하게 흥정하다', '강한 흥정을 몰다', '쉽게 양보하지 않고 끈질기게 좋은 조건을 이끌어낸다는 뜻이에요. 협상이나 사업 거래에서도 자주 써요.', 'She drives a hard bargain at every market.', '그녀는 시장마다 깐깐하게 흥정해요.', 'The supplier drives a hard bargain.', '그 공급업체는 흥정이 만만치 않아요.', NULL, NULL, 'C1', 'shopping', 2, 'market negotiating buyer', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_health_C1_01', 'seek', 'treatment', 'seek treatment', '치료를 받다', 'get', '병원이나 전문가의 도움을 적극적으로 찾는다는 격식 있는 표현이에요. 의료 기사나 상담 자리에서 자주 써요.', 'You should seek treatment as soon as the symptoms worsen.', '증상이 악화되면 즉시 치료를 받아야 해요.', 'Many patients hesitate to seek treatment for mental health issues.', '많은 환자들이 정신 건강 문제로 치료받기를 망설여요.', 'C1', 'health', 2, 'doctor consultation'),
('col_health_C1_02', 'follow', 'doctor''s orders', 'follow doctor''s orders', '의사의 지시를 따르다', 'listen', '처방이나 권고 사항을 충실히 지킨다는 관용적 표현이에요. 격식 있는 회복 안내에서 흔히 써요.', 'She made a full recovery because she followed her doctor''s orders to the letter.', '그녀는 의사의 지시를 철저히 따라서 완전히 회복했어요.', 'Patients who follow doctor''s orders tend to heal faster.', '의사의 지시를 따르는 환자들이 더 빨리 낫는 경향이 있어요.', 'C1', 'health', 2, 'doctor prescription'),
('col_health_C1_03', 'make', 'recovery', 'make a recovery', '회복하다', 'do', '병이나 부상에서 회복하는 과정을 격식 있게 표현해요. ''make a full/speedy/remarkable recovery''처럼 형용사를 자주 동반해요.', 'He made a remarkable recovery after the surgery.', '그는 수술 후에 놀라울 정도로 회복했어요.', 'The patient is expected to make a full recovery within weeks.', '환자는 몇 주 안에 완전히 회복할 것으로 예상돼요.', 'C1', 'health', 2, 'hospital recovery'),
('col_health_C1_04', 'boost', 'immunity', 'boost immunity', '면역력을 높이다', 'increase', '면역 체계를 강화한다는 건강 분야의 전형적인 콜로케이션이에요. 잡지나 광고에서 자주 등장해요.', 'Eating a balanced diet helps boost your immunity during winter.', '균형 잡힌 식단은 겨울철 면역력을 높이는 데 도움이 돼요.', 'Regular exercise has been shown to boost immunity over time.', '규칙적인 운동은 시간이 지나면서 면역력을 높이는 것으로 밝혀졌어요.', 'C1', 'health', 2, 'healthy food vitamins'),
('col_health_C1_05', 'manage', 'stress', 'manage stress', '스트레스를 관리하다', 'control', '스트레스를 완전히 없애기보다 잘 다룬다는 의미예요. 자기계발과 건강 칼럼에서 표준 표현이에요.', 'Meditation can help you manage stress more effectively.', '명상은 스트레스를 더 효과적으로 관리하는 데 도움이 돼요.', 'Learning to manage stress is essential for long-term well-being.', '스트레스 관리법을 배우는 것은 장기적인 웰빙에 필수적이에요.', 'C1', 'health', 2, 'meditation calm')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_health_C1_01', 'on the mend', '회복 중인', '수선되는 중', '아픈 사람이 회복되고 있다는 다정한 표현이에요. 친구나 가족의 안부를 물을 때 자연스럽게 써요.', 'She caught a nasty flu but she''s on the mend now.', '독한 독감에 걸렸지만 지금은 회복 중이에요.', 'I''m glad to hear your father is on the mend.', '아버님이 회복 중이시라니 다행이에요.', 'After a week of rest, he''s finally on the mend.', '일주일간 쉬고 나니 그는 마침내 회복 중이에요.', 'C1', 'health', 2, 'patient resting', 1),
('idm_health_C1_02', 'as fit as a fiddle', '아주 건강한', '바이올린처럼 건강한', '나이에 비해 또는 아픔에서 회복한 뒤 매우 건강한 상태를 묘사해요. 일상 대화에서 가볍게 칭찬할 때 써요.', 'My grandmother is 85 but she''s as fit as a fiddle.', '할머니는 85세이신데 아주 정정하세요.', 'After three months of training, he was as fit as a fiddle.', '3개월간의 훈련 후 그는 아주 건강해졌어요.', 'Despite his age, the marathoner remains as fit as a fiddle.', '나이에도 불구하고 그 마라토너는 여전히 정정해요.', 'C1', 'health', 2, 'fit elderly person', 2),
('idm_health_C1_03', 'under the weather', '몸이 좀 안 좋은', '날씨 아래에', '심하게 아프지는 않지만 컨디션이 좋지 않을 때 써요. 직장에서 결근 사유를 부드럽게 말할 때 자주 써요.', 'I''m feeling a bit under the weather today, so I''ll work from home.', '오늘은 컨디션이 좀 안 좋아서 재택근무할게요.', 'She''s been under the weather all week and skipped the gym.', '그녀는 일주일 내내 컨디션이 안 좋아서 헬스장을 빠졌어요.', 'If you''re under the weather, please don''t push yourself.', '컨디션이 안 좋으시면 무리하지 마세요.', 'C1', 'health', 2, 'tired person tea', 3),
('idm_health_C1_04', 'a clean bill of health', '건강 이상 없음 판정', '깨끗한 건강 증명서', '검진 결과 아무 문제가 없다는 의학적 평가를 가리켜요. 정기 검진이나 사업 비유에서도 자주 등장해요.', 'The doctor gave him a clean bill of health after the annual checkup.', '의사는 그에게 건강 검진 후 이상 없음 판정을 내렸어요.', 'I won''t relax until I get a clean bill of health.', '건강 이상 없음 판정을 받기 전까지는 안심이 안 돼요.', 'The auditors gave the company a clean bill of health.', '감사관들은 회사에 아무 문제가 없다고 판정했어요.', 'C1', 'health', 2, 'medical checkup', 4),
('idm_health_C1_05', 'the picture of health', '건강 그 자체', '건강의 그림', '겉으로 보기에도 매우 건강해 보이는 사람을 묘사할 때 써요. 칭찬이나 묘사적 글에서 자연스러워요.', 'Tanned and smiling, she was the picture of health.', '햇볕에 그을리고 환하게 웃는 그녀는 건강 그 자체였어요.', 'At 70, he looks the picture of health.', '70세인 그는 건강 그 자체로 보여요.', 'After her holiday, she returned the picture of health.', '휴가 후에 그녀는 건강 그 자체로 돌아왔어요.', 'C1', 'health', 2, 'healthy smiling person', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_weather_C1_01', 'brave', 'cold', 'brave the cold', '추위를 무릅쓰다', 'face', '나쁜 날씨를 용감하게 견뎌낸다는 다소 문어적 표현이에요. 뉴스 기사나 여행기에 자주 등장해요.', 'Thousands braved the cold to watch the parade.', '수천 명이 추위를 무릅쓰고 퍼레이드를 봤어요.', 'We braved the cold for a sunrise hike up the mountain.', '우리는 추위를 무릅쓰고 일출 등산을 했어요.', 'C1', 'weather', 2, 'people in snow coats'),
('col_weather_C1_02', 'battle', 'heat', 'battle the heat', '더위와 싸우다', 'fight', '극심한 더위에 맞서 버틴다는 비유적 표현이에요. 여름 기사나 스포츠 보도에서 자주 써요.', 'Construction workers battle the heat throughout July and August.', '건설 노동자들은 7월과 8월 내내 더위와 싸워요.', 'Marathon runners had to battle the heat during the final stretch.', '마라톤 선수들은 마지막 구간에서 더위와 싸워야 했어요.', 'C1', 'weather', 2, 'hot summer sun'),
('col_weather_C1_03', 'endure', 'downpour', 'endure a downpour', '폭우를 견뎌내다', 'pass', '강한 비를 오랜 시간 참고 견딘다는 격식 있는 표현이에요. 야외 행사 보도나 여행기에서 자주 써요.', 'Spectators endured a torrential downpour to witness the match.', '관중들은 경기를 보기 위해 억수같은 폭우를 견뎌냈어요.', 'We endured a downpour while waiting for the bus.', '버스를 기다리며 폭우를 견뎌냈어요.', 'C1', 'weather', 2, 'heavy rain crowd'),
('col_weather_C1_04', 'shelter', 'rain', 'shelter from rain', '비를 피하다', 'hide', '비를 피하기 위해 잠시 어딘가에 들어간다는 자연스러운 표현이에요. ''hide''는 약간 부자연스러워요.', 'We sheltered from the rain under a shop awning.', '우리는 가게 차양 아래에서 비를 피했어요.', 'Hikers sheltered from the rain in a nearby cabin.', '등산객들은 근처 오두막에서 비를 피했어요.', 'C1', 'weather', 2, 'rain shelter awning'),
('col_weather_C1_05', 'wrap', 'up warm', 'wrap up warm', '따뜻하게 껴입다', 'dress', '추운 날 두꺼운 옷으로 몸을 감싼다는 영국식 표현이에요. ''dress warm''보다 훨씬 자연스러워요.', 'Wrap up warm — it''s freezing outside.', '따뜻하게 껴입어요. 밖이 정말 추워요.', 'The children wrapped up warm before heading out to play in the snow.', '아이들은 눈 속에서 놀러 나가기 전에 따뜻하게 껴입었어요.', 'C1', 'weather', 2, 'winter coat scarf')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_weather_C1_01', 'a perfect storm', '여러 악재가 겹친 상황', '완벽한 폭풍', '여러 부정적 요소들이 동시에 겹쳐 최악의 상황을 만들었다는 뜻이에요. 뉴스와 비즈니스 분석에서 매우 자주 써요.', 'Rising costs and falling demand created a perfect storm for the industry.', '비용 상승과 수요 감소가 그 산업에 최악의 상황을 만들었어요.', 'The economy is facing a perfect storm of inflation and unemployment.', '경제는 인플레이션과 실업이 겹친 최악의 상황에 직면해 있어요.', 'It was a perfect storm of bad decisions and bad luck.', '잘못된 결정과 불운이 겹친 최악의 상황이었어요.', 'C1', 'weather', 2, 'storm clouds dramatic', 1),
('idm_weather_C1_02', 'under the weather', '몸이 좀 안 좋은', '날씨 아래에', '몸이 살짝 아프거나 컨디션이 안 좋을 때 부드럽게 표현해요. 격식과 비격식 모두에서 자연스러워요.', 'I''m feeling a bit under the weather, so I''ll skip dinner.', '컨디션이 좀 안 좋아서 저녁은 거를게요.', 'He''s been under the weather since Monday.', '그는 월요일부터 컨디션이 안 좋아요.', 'If you''re under the weather, take the day off.', '컨디션이 안 좋으면 하루 쉬세요.', 'C1', 'weather', 2, 'sick person bed', 2),
('idm_weather_C1_03', 'calm before the storm', '폭풍 전의 고요', '폭풍 전의 고요', '큰 사건이나 혼란이 닥치기 직전의 일시적인 평온함을 뜻해요. 뉴스, 비즈니스, 일상 대화에서 두루 써요.', 'The office is unusually quiet — it''s the calm before the storm.', '사무실이 이상하게 조용해요. 폭풍 전의 고요예요.', 'Enjoy this calm before the storm; tomorrow will be hectic.', '폭풍 전의 고요를 즐기세요. 내일은 정신없을 거예요.', 'The calm before the storm lasted only an hour.', '폭풍 전의 고요는 한 시간밖에 지속되지 않았어요.', 'C1', 'weather', 2, 'calm sea before storm', 3),
('idm_weather_C1_04', 'raining cats and dogs', '비가 억수같이 오는', '고양이와 개가 비처럼 내리는', '비가 매우 세차게 내릴 때 쓰는 전형적인 영어 관용구예요. 친근한 대화에서 흔히 써요.', 'You can''t go out now — it''s raining cats and dogs!', '지금 나가면 안 돼요. 비가 억수같이 와요!', 'It was raining cats and dogs when we left the theater.', '극장을 나올 때 비가 억수같이 왔어요.', 'Bring an umbrella; it''s raining cats and dogs out there.', '우산 챙기세요. 밖에 비가 억수같이 와요.', 'C1', 'weather', 2, 'heavy downpour street', 4),
('idm_weather_C1_05', 'a fair-weather friend', '잘 나갈 때만 친한 친구', '좋은 날씨일 때만의 친구', '내가 어려울 때는 멀어지고, 잘 지낼 때만 가까이 오는 사람을 뜻해요. 약간의 비판적 뉘앙스가 있어요.', 'When I lost my job, I realized he was just a fair-weather friend.', '제가 일자리를 잃었을 때 그가 잘 나갈 때만의 친구였다는 걸 깨달았어요.', 'True friends stand by you; fair-weather friends disappear.', '진정한 친구는 곁에 있어주고, 잘 나갈 때만의 친구는 사라져요.', 'Don''t waste your loyalty on fair-weather friends.', '잘 나갈 때만의 친구에게 의리를 낭비하지 마세요.', 'C1', 'weather', 2, 'two friends sunshine', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_transport_C1_01', 'hail', 'cab', 'hail a cab', '택시를 잡다', 'call', '길에서 손을 들어 지나가는 택시를 세운다는 의미예요. ''call''은 전화로 부르는 거라 어감이 달라요.', 'It''s nearly impossible to hail a cab in this rainstorm.', '이 폭우 속에서는 택시를 잡기가 거의 불가능해요.', 'She stepped onto the curb and hailed a cab.', '그녀는 인도로 나가서 택시를 잡았어요.', 'C1', 'transport', 2, 'hailing taxi street'),
('col_transport_C1_02', 'miss', 'bus', 'miss the bus', '버스를 놓치다', 'lose', '교통수단을 시간 안에 못 타는 것은 ''miss''를 써요. ''lose''는 의미가 달라져요.', 'I missed the last bus and had to walk home.', '막차를 놓쳐서 집까지 걸어가야 했어요.', 'If we don''t leave now, we''ll miss the bus.', '지금 출발하지 않으면 버스를 놓칠 거예요.', 'C1', 'transport', 2, 'missed bus stop'),
('col_transport_C1_03', 'catch', 'train', 'catch the train', '기차를 잡아타다', 'take', '출발 직전의 기차를 타는 데 성공한다는 뉘앙스예요. ''take the train''보다 시간 압박이 있어요.', 'We caught the train just before it left the platform.', '우리는 기차가 플랫폼을 떠나기 직전에 잡아탔어요.', 'Hurry, or we won''t catch the train.', '서둘러요, 안 그러면 기차를 못 타요.', 'C1', 'transport', 2, 'train platform departure'),
('col_transport_C1_04', 'navigate', 'traffic', 'navigate traffic', '교통 체증을 헤쳐 나가다', 'pass', '혼잡한 도로를 능숙하게 운전해 빠져나간다는 표현이에요. 격식 있는 글이나 운전 칼럼에서 자주 써요.', 'Experienced drivers know how to navigate traffic during rush hour.', '능숙한 운전자는 출퇴근 시간에 교통 체증을 헤쳐 나갈 줄 알아요.', 'It took us two hours to navigate the city traffic.', '도심 교통을 헤쳐 나가는 데 두 시간이 걸렸어요.', 'C1', 'transport', 2, 'city traffic jam'),
('col_transport_C1_05', 'make', 'connections', 'make connections', '환승하다', 'change', '비행기, 기차 등을 갈아탄다는 격식 있는 표현이에요. 항공 안내나 여행기에서 자주 등장해요.', 'Passengers must make connections in Frankfurt before flying to Seoul.', '승객들은 서울행 비행 전에 프랑크푸르트에서 환승해야 해요.', 'I had only 30 minutes to make connections at the airport.', '공항에서 환승할 시간이 30분밖에 없었어요.', 'C1', 'transport', 2, 'airport connection terminal')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_transport_C1_01', 'hit the road', '출발하다', '길을 치다', '여행이나 외출을 시작한다는 캐주얼하지만 표준적인 관용 표현이에요. 친구들과의 대화에서 자연스러워요.', 'It''s getting late — we should hit the road.', '늦어지고 있네요. 이제 출발해요.', 'We hit the road at dawn to beat the traffic.', '우리는 교통 체증을 피하려고 새벽에 출발했어요.', 'Pack your bags; we hit the road tomorrow.', '짐 싸세요. 내일 출발해요.', 'C1', 'transport', 2, 'road trip car', 1),
('idm_transport_C1_02', 'out of pocket', '자비로 부담한', '주머니 밖의', '자기 돈으로 비용을 부담했다는 의미예요. 비즈니스나 출장 비용 정산에서 자주 써요.', 'I was out of pocket for the taxi fare during the business trip.', '출장 중 택시비를 자비로 부담했어요.', 'Don''t worry — you won''t be out of pocket; the company will reimburse you.', '걱정 마세요. 자비 부담은 없을 거예요. 회사가 환급해 줄 거예요.', 'She was out of pocket by 200 dollars after the trip.', '여행 후 그녀는 200달러를 자비로 부담했어요.', 'C1', 'transport', 2, 'wallet money receipt', 2),
('idm_transport_C1_03', 'miss the boat', '기회를 놓치다', '배를 놓치다', '좋은 기회를 너무 늦게 알아서 놓쳤다는 뜻이에요. 비즈니스, 투자, 여행 등 다양한 상황에서 써요.', 'If you don''t book early, you''ll miss the boat on cheap flights.', '미리 예약하지 않으면 저렴한 항공권 기회를 놓칠 거예요.', 'Investors who hesitated missed the boat on the tech boom.', '망설였던 투자자들은 IT 붐의 기회를 놓쳤어요.', 'Don''t miss the boat — sign up before the discount ends.', '기회를 놓치지 마세요. 할인이 끝나기 전에 신청하세요.', 'C1', 'transport', 2, 'boat leaving dock', 3),
('idm_transport_C1_04', 'off the beaten path', '잘 알려지지 않은', '많이 다닌 길에서 벗어난', '관광객들이 잘 가지 않는 숨겨진 장소를 가리켜요. 여행 잡지와 블로그에서 표준 표현이에요.', 'This little village is wonderfully off the beaten path.', '이 작은 마을은 정말 잘 알려지지 않은 곳이에요.', 'We prefer destinations off the beaten path.', '우리는 잘 알려지지 않은 곳을 선호해요.', 'The café is off the beaten path but worth the detour.', '그 카페는 잘 알려지지 않은 곳이지만 돌아갈 만한 가치가 있어요.', 'C1', 'transport', 2, 'hidden village trail', 4),
('idm_transport_C1_05', 'go off the rails', '엇나가다', '레일에서 벗어나다', '계획이나 사람의 삶이 정상 궤도를 벗어나 잘못된 방향으로 간다는 뜻이에요. 뉴스와 일상 대화 모두에서 써요.', 'The project went off the rails after the manager quit.', '매니저가 그만둔 후 프로젝트가 엇나가기 시작했어요.', 'His career went off the rails during the scandal.', '그의 경력은 스캔들 중 엇나가기 시작했어요.', 'The negotiations have gone completely off the rails.', '협상이 완전히 엇나갔어요.', 'C1', 'transport', 2, 'derailed train tracks', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_media_C1_01', 'go', 'viral', 'go viral', '입소문 나다', 'become', '콘텐츠가 인터넷에서 급속도로 퍼지는 현상을 뜻해요. 미디어, 마케팅 분야의 핵심 표현이에요.', 'Her dance video went viral overnight.', '그녀의 댄스 영상은 하룻밤 사이에 입소문이 났어요.', 'Brands dream of creating content that goes viral.', '브랜드들은 입소문 나는 콘텐츠를 만드는 걸 꿈꿔요.', 'C1', 'media', 2, 'viral video phone'),
('col_media_C1_02', 'draw', 'attention', 'draw attention', '주목을 끌다', 'pull', '사람들의 시선이나 관심을 모은다는 격식 있는 표현이에요. 뉴스, 광고, 학술 글에서 두루 써요.', 'The documentary drew attention to climate change.', '그 다큐멘터리는 기후 변화에 대한 주목을 끌었어요.', 'The campaign successfully drew attention to youth literacy.', '그 캠페인은 청소년 문해력 문제에 성공적으로 주목을 끌었어요.', 'C1', 'media', 2, 'spotlight news camera'),
('col_media_C1_03', 'shape', 'narrative', 'shape the narrative', '담론을 형성하다', 'make', '이야기나 여론의 흐름을 의도적으로 만든다는 정치·미디어 분야의 핵심 표현이에요.', 'Social media now shapes the narrative around political events.', '소셜 미디어는 이제 정치 이슈의 담론을 형성해요.', 'Public relations teams work to shape the narrative.', '홍보팀은 담론을 형성하기 위해 노력해요.', 'C1', 'media', 2, 'news headlines media'),
('col_media_C1_04', 'stir', 'controversy', 'stir controversy', '논란을 일으키다', 'cause', '사회적으로 뜨거운 논쟁을 불러일으킨다는 격식 있는 저널리즘 표현이에요.', 'The advertisement stirred controversy across social media.', '그 광고는 소셜 미디어 전반에 논란을 일으켰어요.', 'His remarks stirred controversy among critics.', '그의 발언은 비평가들 사이에 논란을 일으켰어요.', 'C1', 'media', 2, 'controversial news'),
('col_media_C1_05', 'make', 'headlines', 'make headlines', '머리기사를 장식하다', 'get', '사건이 신문 1면을 차지할 만큼 큰 화제가 된다는 의미예요. 뉴스 보도와 일상 대화에서 모두 써요.', 'The merger made headlines around the world.', '그 합병은 전 세계 머리기사를 장식했어요.', 'Her humanitarian work made headlines last week.', '그녀의 인도주의적 활동이 지난주 머리기사를 장식했어요.', 'C1', 'media', 2, 'newspaper front page')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_media_C1_01', 'in the spotlight', '주목받는', '스포트라이트 안에', '대중이나 언론의 관심을 한 몸에 받는 상태를 뜻해요. 연예, 정치, 비즈니스 모든 분야에서 써요.', 'The young actress found herself in the spotlight after the film''s release.', '그 어린 여배우는 영화 개봉 후 주목을 받게 되었어요.', 'CEOs are constantly in the spotlight.', 'CEO들은 끊임없이 주목받아요.', 'Being in the spotlight is not always a blessing.', '주목받는 것이 항상 축복은 아니에요.', 'C1', 'media', 2, 'spotlight stage performer', 1),
('idm_media_C1_02', 'behind the scenes', '비공식적으로, 무대 뒤에서', '장면 뒤에서', '공식적으로 드러나지 않는 곳에서 일이 진행된다는 의미예요. 비즈니스와 미디어 보도에서 표준 표현이에요.', 'A lot of negotiation happens behind the scenes.', '많은 협상이 비공식적으로 이루어져요.', 'Behind the scenes, the team worked tirelessly on the launch.', '뒤에서는 팀이 출시를 위해 쉴 새 없이 일했어요.', 'The documentary shows what happens behind the scenes.', '그 다큐멘터리는 무대 뒤에서 일어나는 일을 보여줘요.', 'C1', 'media', 2, 'film crew behind scenes', 2),
('idm_media_C1_03', 'make a splash', '큰 화제를 일으키다', '물 튀기다', '강한 인상을 남기며 주목받는다는 뜻이에요. 신제품 출시, 데뷔, 발표 등에 자주 써요.', 'The new app made a splash in the tech industry.', '그 새 앱은 IT 업계에서 큰 화제를 일으켰어요.', 'Her debut novel made quite a splash.', '그녀의 데뷔 소설은 상당한 화제를 일으켰어요.', 'The brand made a splash with its bold campaign.', '그 브랜드는 대담한 캠페인으로 큰 화제를 일으켰어요.', 'C1', 'media', 2, 'splashing water impact', 3),
('idm_media_C1_04', 'the talk of the town', '동네의 화젯거리', '동네의 이야기', '많은 사람들이 화제 삼아 이야기하는 인물이나 사건을 가리켜요. 일상 대화에서 자연스럽게 써요.', 'The new restaurant is the talk of the town.', '그 새 식당이 동네의 화젯거리예요.', 'Her surprise wedding became the talk of the town.', '그녀의 깜짝 결혼식이 동네의 화젯거리가 됐어요.', 'That scandal was the talk of the town for weeks.', '그 스캔들은 몇 주간 동네의 화젯거리였어요.', 'C1', 'media', 2, 'town gossip people', 4),
('idm_media_C1_05', 'no smoke without fire', '아니 땐 굴뚝에 연기 나랴', '불 없이 연기 없다', '소문이 돈다면 그 안에 어느 정도 사실이 있다는 뜻이에요. 토론이나 가십 분석에서 자주 인용돼요.', 'There must be some truth to the rumors — no smoke without fire.', '그 소문에는 어느 정도 사실이 있을 거예요. 아니 땐 굴뚝에 연기 나겠어요.', 'I don''t trust him; there''s no smoke without fire.', '그를 못 믿겠어요. 아니 땐 굴뚝에 연기 나겠어요.', 'As they say, no smoke without fire — investigators are looking into it.', '말 그대로 아니 땐 굴뚝에 연기 안 나죠. 조사관들이 들여다보고 있어요.', 'C1', 'media', 2, 'smoke rising chimney', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_education_C1_01', 'earn', 'degree', 'earn a degree', '학위를 취득하다', 'get', '시간과 노력을 들여 학위를 받았다는 격식 있는 표현이에요. ''get a degree''보다 더 무게감 있게 들려요.', 'She earned a master''s degree in linguistics.', '그녀는 언어학 석사 학위를 취득했어요.', 'He earned his degree while working full-time.', '그는 풀타임으로 일하면서 학위를 취득했어요.', 'C1', 'education', 2, 'graduation diploma'),
('col_education_C1_02', 'broaden', 'horizons', 'broaden horizons', '시야를 넓히다', 'open', '경험이나 학습을 통해 사고와 관점을 확장한다는 의미예요. 교육·여행 분야에서 매우 자주 써요.', 'Studying abroad really broadens your horizons.', '해외 유학은 시야를 정말 넓혀줘요.', 'Reading widely is one of the best ways to broaden your horizons.', '폭넓게 읽는 것은 시야를 넓히는 가장 좋은 방법 중 하나예요.', 'C1', 'education', 2, 'student abroad horizon'),
('col_education_C1_03', 'grasp', 'concept', 'grasp a concept', '개념을 이해하다', 'catch', '추상적인 개념을 정확히 이해한다는 학술적 표현이에요. ''catch''는 부자연스러워요.', 'Most students grasp the concept of supply and demand quickly.', '대부분의 학생들은 수요와 공급 개념을 빠르게 이해해요.', 'It took me a while to grasp the concept of quantum mechanics.', '양자역학 개념을 이해하는 데 시간이 좀 걸렸어요.', 'C1', 'education', 2, 'student understanding book'),
('col_education_C1_04', 'master', 'subject', 'master a subject', '한 과목을 통달하다', 'learn', '단순히 배우는 것을 넘어 매우 깊이 있게 익혔다는 뜻이에요. 학업과 전문 분야에서 두루 써요.', 'It takes years of practice to master a subject like calculus.', '미적분 같은 과목을 통달하는 데는 수년간의 연습이 필요해요.', 'She has mastered the subject of medieval history.', '그녀는 중세사 분야를 통달했어요.', 'C1', 'education', 2, 'student studying mastery'),
('col_education_C1_05', 'ace', 'exam', 'ace an exam', '시험을 잘 보다', 'win', '시험을 매우 잘 봐서 최고 점수를 받는다는 미국식 표현이에요. 캐주얼하지만 C1 수준에서 흔히 써요.', 'She aced her final exam without breaking a sweat.', '그녀는 땀 한 방울 흘리지 않고 기말고사를 잘 봤어요.', 'If you study hard, you''ll ace the exam.', '열심히 공부하면 시험을 잘 볼 거예요.', 'C1', 'education', 2, 'exam test perfect score')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_education_C1_01', 'hit the books', '공부에 매진하다', '책을 치다', '공부를 본격적으로 시작하거나 열심히 한다는 친근한 학생 표현이에요. 대학생들 사이에서 매우 자연스러워요.', 'Finals are next week — time to hit the books.', '다음 주가 기말이에요. 이제 공부에 매진할 때예요.', 'I can''t go out tonight; I have to hit the books.', '오늘 밤은 못 나가요. 공부해야 해요.', 'She''s been hitting the books for weeks.', '그녀는 몇 주째 공부에 매진하고 있어요.', 'C1', 'education', 2, 'student studying books', 1),
('idm_education_C1_02', 'make the grade', '기준에 부합하다', '학점을 만들다', '요구되는 수준이나 기준에 도달한다는 뜻이에요. 학업뿐 아니라 직장과 스포츠에서도 자주 써요.', 'Only a handful of applicants made the grade.', '극소수의 지원자만이 기준에 부합했어요.', 'You need to study harder to make the grade.', '기준에 부합하려면 더 열심히 공부해야 해요.', 'The team didn''t quite make the grade for the playoffs.', '그 팀은 플레이오프 기준에 살짝 못 미쳤어요.', 'C1', 'education', 2, 'report card grade', 2),
('idm_education_C1_03', 'old school', '구식의, 전통적인', '오래된 학교', '전통적이고 옛 방식을 고수한다는 뜻으로, 종종 긍정적이고 멋스럽다는 뉘앙스도 가져요. 패션, 음악, 교육 등 다양한 분야에서 써요.', 'My professor is very old school — no laptops in class.', '제 교수님은 굉장히 구식이에요. 수업에 노트북도 못 가져와요.', 'He prefers an old-school approach to teaching.', '그는 구식의 교육 방식을 선호해요.', 'There''s something charming about her old-school manners.', '그녀의 구식 매너에는 매력적인 면이 있어요.', 'C1', 'education', 2, 'vintage classroom', 3),
('idm_education_C1_04', 'learn the ropes', '요령을 배우다', '밧줄을 배우다', '새로운 일이나 환경의 기본을 익힌다는 뜻이에요. 신입사원이나 새로운 학생에게 흔히 써요.', 'It took me a few months to learn the ropes at the new job.', '새 직장에서 요령을 배우는 데 몇 달 걸렸어요.', 'Don''t worry — you''ll learn the ropes soon enough.', '걱정 마세요. 곧 요령을 익힐 거예요.', 'The mentor helped her learn the ropes quickly.', '멘토 덕분에 그녀는 빠르게 요령을 익혔어요.', 'C1', 'education', 2, 'mentor training new hire', 4),
('idm_education_C1_05', 'pass with flying colors', '우수한 성적으로 통과하다', '깃발을 휘날리며 통과하다', '시험이나 평가를 매우 훌륭하게 통과했다는 격식 있는 표현이에요. 학업과 검증 절차 모두에서 써요.', 'She passed her driving test with flying colors.', '그녀는 우수한 성적으로 운전 면허 시험을 통과했어요.', 'The product passed safety inspections with flying colors.', '그 제품은 안전 검사를 우수하게 통과했어요.', 'He passed the bar exam with flying colors.', '그는 변호사 시험을 우수한 성적으로 통과했어요.', 'C1', 'education', 2, 'success colorful flags', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_economy_C1_01', 'boost', 'growth', 'boost growth', '성장을 촉진하다', 'rise', '경제 성장률을 끌어올린다는 표준 표현이에요. 정책, 투자, 무역 관련 기사에서 자주 등장해요.', 'The central bank lowered rates to boost growth in the manufacturing sector.', '중앙은행은 제조업 성장을 촉진하기 위해 금리를 인하했어요.', 'Tax incentives are designed to boost growth among small businesses.', '세제 혜택은 중소기업 성장을 촉진하기 위해 설계됐어요.', 'C1', 'economy', 2, 'rising chart'),
('col_economy_C1_02', 'tackle', 'inflation', 'tackle inflation', '인플레이션에 대응하다', 'fight', '''fight''도 가능하지만 ''tackle''이 정책적·전략적으로 문제를 다룬다는 뉘앙스라 신문에서 더 흔해요.', 'The government unveiled a new package to tackle inflation and stabilize prices.', '정부는 인플레이션에 대응하고 물가를 안정시키기 위한 새 패키지를 공개했어요.', 'Policymakers are under pressure to tackle inflation without triggering a recession.', '정책 입안자들은 경기 침체를 유발하지 않고 인플레이션에 대응해야 한다는 압박을 받고 있어요.', 'C1', 'economy', 2, 'inflation chart'),
('col_economy_C1_03', 'raise', 'interest rates', 'raise interest rates', '금리를 인상하다', 'lift', '중앙은행이 기준 금리를 올린다는 정확한 표현이에요. ''lift''는 일상 영어라 금융 보도에는 어울리지 않아요.', 'The Federal Reserve is expected to raise interest rates again next quarter.', '연준은 다음 분기에 다시 금리를 인상할 것으로 예상돼요.', 'Raising interest rates too quickly could slow the housing market.', '금리를 너무 빨리 인상하면 주택 시장이 둔화될 수 있어요.', 'C1', 'economy', 2, 'federal reserve'),
('col_economy_C1_04', 'spur', 'demand', 'spur demand', '수요를 자극하다', 'make', '소비자 수요를 단시간에 늘린다는 격식 있는 표현이에요. 마케팅이나 정책 보고서에 자주 써요.', 'Holiday discounts spurred demand for electronics across the region.', '연휴 할인이 지역 전반에 걸쳐 전자제품 수요를 자극했어요.', 'Government subsidies have spurred demand for electric vehicles.', '정부 보조금이 전기차 수요를 자극했어요.', 'C1', 'economy', 2, 'shopping demand'),
('col_economy_C1_05', 'rebound', 'recession', 'rebound from recession', '불황에서 회복하다', 'come', '경제가 침체기 이후 다시 활기를 되찾는다는 표현이에요. 분기 실적이나 거시 경제 분석에 자주 나와요.', 'The economy is finally rebounding from the deepest recession in a decade.', '경제가 마침내 10년 만의 가장 깊은 불황에서 회복하고 있어요.', 'Tourism has rebounded from the recession faster than analysts predicted.', '관광업은 분석가들의 예상보다 빠르게 불황에서 회복했어요.', 'C1', 'economy', 2, 'economic recovery')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_economy_C1_01', 'tighten your belt', '허리띠를 졸라매다', '벨트를 조이다', '지출을 줄이고 절약 생활을 한다는 뜻이에요. 개인 재정과 기업 비용 절감 양쪽에 다 써요.', 'Many households have had to tighten their belts as energy prices surged.', '에너지 가격이 급등하면서 많은 가정이 허리띠를 졸라매야 했어요.', 'The company is tightening its belt by freezing all non-essential spending.', '회사는 비필수 지출을 모두 동결하며 허리띠를 졸라매고 있어요.', 'We may need to tighten our belts until the bonus comes through.', '보너스가 나올 때까지 허리띠를 졸라매야 할 수도 있어요.', 'C1', 'economy', 2, 'tight belt', 1),
('idm_economy_C1_02', 'make ends meet', '겨우 먹고살다', '양쪽 끝을 만나게 하다', '수입이 빠듯해서 겨우 생활비를 충당한다는 뜻이에요. 인터뷰나 사회 기사에서 자주 등장해요.', 'With rent rising, many young workers struggle to make ends meet.', '월세가 오르면서 많은 청년 근로자가 겨우 먹고살기도 힘들어해요.', 'She took on a second job just to make ends meet.', '그녀는 겨우 생활비를 충당하려고 부업을 하나 더 시작했어요.', 'Single parents often find it hard to make ends meet on one salary.', '한부모 가정은 한 사람 월급으로 생활하기 어려운 경우가 많아요.', 'C1', 'economy', 2, 'wallet budget', 2),
('idm_economy_C1_03', 'in the red', '적자 상태인', '빨간색 안에 있는', '회계상 손실 상태를 가리키는 표준 표현이에요. 회사 실적이나 개인 계좌 모두에 써요.', 'The airline has been in the red for three consecutive quarters.', '그 항공사는 3분기 연속 적자 상태예요.', 'Her checking account slipped into the red after the unexpected bill.', '예상치 못한 청구서로 그녀의 입출금 계좌가 적자로 돌아섰어요.', 'Several startups remain in the red despite strong revenue growth.', '여러 스타트업이 매출 성장에도 불구하고 적자 상태에 머물러 있어요.', 'C1', 'economy', 2, 'red financial chart', 3),
('idm_economy_C1_04', 'in the black', '흑자 상태인', '검은색 안에 있는', '''in the red''의 반대로, 이익을 내고 있다는 뜻이에요. 분기 실적 발표에서 자주 들을 수 있어요.', 'After two tough years, the firm is finally back in the black.', '힘든 2년을 보낸 끝에 그 회사는 마침내 흑자로 돌아왔어요.', 'The streaming division has been in the black since last spring.', '스트리밍 사업부는 지난봄부터 흑자 상태예요.', 'Cost-cutting measures pushed the bank firmly into the black.', '비용 절감 조치로 그 은행은 확실한 흑자 상태가 됐어요.', 'C1', 'economy', 2, 'profit chart', 4),
('idm_economy_C1_05', 'a penny saved is a penny earned', '한 푼을 아끼면 한 푼을 번 것', '아낀 1페니는 번 1페니와 같다', '절약이 곧 수입이라는 격언이에요. 재테크 칼럼이나 가족 간 대화에서 자연스럽게 써요.', 'My grandmother always said that a penny saved is a penny earned.', '저희 할머니는 늘 한 푼을 아끼면 한 푼을 번 것이라고 말씀하셨어요.', 'Investing in energy-efficient appliances pays off — a penny saved is a penny earned.', '에너지 효율 가전에 투자하는 건 보람이 있어요. 한 푼을 아끼면 한 푼을 번 것이니까요.', 'In this economy, a penny saved really is a penny earned.', '요즘 같은 경제에서는 한 푼을 아끼는 게 정말 버는 것과 같아요.', 'C1', 'economy', 2, 'penny coin jar', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_technology_C1_01', 'adopt', 'innovation', 'adopt innovation', '혁신을 도입하다', 'take', '새로운 기술이나 방식을 조직 차원에서 받아들인다는 뜻이에요. 비즈니스 보고서의 표준 표현이에요.', 'Hospitals have been slow to adopt innovation in patient record systems.', '병원들은 환자 기록 시스템 혁신을 도입하는 데 느렸어요.', 'Successful firms continually adopt innovation to stay competitive.', '성공하는 기업은 경쟁력을 유지하기 위해 끊임없이 혁신을 도입해요.', 'C1', 'technology', 2, 'modern office tech'),
('col_technology_C1_02', 'integrate', 'systems', 'integrate systems', '시스템을 통합하다', 'join', '서로 다른 IT 시스템을 하나로 연동시킨다는 기술 표현이에요. ''join''은 단순 결합이라 정확하지 않아요.', 'The acquisition will require us to integrate systems across three continents.', '이번 인수로 3개 대륙에 걸친 시스템을 통합해야 해요.', 'It took six months to fully integrate the new CRM system with our database.', '새 CRM 시스템을 우리 데이터베이스와 완전히 통합하는 데 6개월이 걸렸어요.', 'C1', 'technology', 2, 'server room'),
('col_technology_C1_03', 'deploy', 'software', 'deploy software', '소프트웨어를 배포하다', 'put', '소프트웨어를 운영 환경에 설치하고 가동시킨다는 IT 표준 동사예요. ''put''은 너무 일상적이에요.', 'The team will deploy the software update across all servers tonight.', '팀은 오늘 밤 모든 서버에 소프트웨어 업데이트를 배포할 거예요.', 'We deploy software in stages to minimize disruption.', '우리는 지장을 최소화하기 위해 단계적으로 소프트웨어를 배포해요.', 'C1', 'technology', 2, 'developer screen'),
('col_technology_C1_04', 'tackle', 'bugs', 'tackle bugs', '버그를 해결하다', 'kill', '''kill bugs''도 쓰이지만, ''tackle''이 체계적으로 문제를 해결한다는 전문적인 뉘앙스라 더 격식 있어요.', 'Our QA engineers are tackling the most critical bugs before launch.', '우리 QA 엔지니어들이 출시 전에 가장 심각한 버그를 해결하고 있어요.', 'The patch tackles several long-standing bugs reported by users.', '이 패치는 사용자들이 보고한 여러 고질적인 버그를 해결해요.', 'C1', 'technology', 2, 'debugging code'),
('col_technology_C1_05', 'scale', 'operations', 'scale operations', '운영 규모를 확장하다', 'grow', '''grow''는 일반적이지만, ''scale''은 효율을 유지하며 규모를 키운다는 스타트업/테크 용어예요.', 'Cloud infrastructure allows startups to scale operations rapidly.', '클라우드 인프라 덕분에 스타트업이 운영 규모를 빠르게 확장할 수 있어요.', 'We need a better hiring strategy before we scale operations into Asia.', '아시아로 운영을 확장하기 전에 더 나은 채용 전략이 필요해요.', 'C1', 'technology', 2, 'data center')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_technology_C1_01', 'cutting edge', '최첨단의', '날카로운 가장자리', '가장 앞선 기술이나 발전을 뜻해요. 형용사처럼 ''cutting-edge''로 자주 써요.', 'Their lab develops cutting-edge AI tools used by researchers worldwide.', '그들의 연구실은 전 세계 연구자들이 쓰는 최첨단 AI 도구를 개발해요.', 'The new headset is at the cutting edge of virtual reality.', '새 헤드셋은 가상현실의 최첨단에 있어요.', 'She wants to work somewhere on the cutting edge of biotech.', '그녀는 생명공학 최첨단 분야에서 일하고 싶어 해요.', 'C1', 'technology', 2, 'futuristic tech', 1),
('idm_technology_C1_02', 'tech savvy', '기술에 밝은', '기술 능숙한', '디지털 기기와 소프트웨어를 능숙하게 다룬다는 뜻이에요. 채용 공고나 일상 대화에 자연스럽게 써요.', 'You do not need to be tech savvy to use the new app — it is very intuitive.', '새 앱을 쓰는 데 기술에 밝을 필요는 없어요. 매우 직관적이에요.', 'Our marketing team is increasingly tech savvy thanks to ongoing training.', '저희 마케팅팀은 꾸준한 교육 덕분에 점점 기술에 밝아지고 있어요.', 'Tech-savvy consumers expect seamless mobile experiences.', '기술에 밝은 소비자들은 매끄러운 모바일 경험을 기대해요.', 'C1', 'technology', 2, 'person using laptop', 2),
('idm_technology_C1_03', 'out of date', '구식의', '날짜 밖의', '더 이상 최신이 아니라는 뜻이에요. 소프트웨어, 정보, 디자인 등에 폭넓게 써요.', 'This operating system is out of date and no longer receives security patches.', '이 운영체제는 구식이라 더 이상 보안 패치를 받지 못해요.', 'Their website looks badly out of date compared to competitors.', '그들의 웹사이트는 경쟁사에 비해 한참 구식으로 보여요.', 'Most of the data in the report is already out of date.', '보고서 데이터 대부분이 이미 구식이에요.', 'C1', 'technology', 2, 'old computer', 3),
('idm_technology_C1_04', 'user friendly', '사용하기 쉬운', '사용자 친화적인', '복잡한 기능 없이 누구나 쉽게 쓸 수 있다는 뜻이에요. 제품 리뷰의 표준 표현이에요.', 'The redesign made the app significantly more user friendly.', '새 디자인 덕분에 앱이 훨씬 더 사용하기 쉬워졌어요.', 'We prioritize user-friendly interfaces in every product we ship.', '저희는 모든 제품에서 사용하기 쉬운 인터페이스를 우선시해요.', 'Older customers appreciate how user friendly the device is.', '연령대가 높은 고객들은 그 기기가 얼마나 쓰기 쉬운지를 좋아해요.', 'C1', 'technology', 2, 'simple interface', 4),
('idm_technology_C1_05', 'push the boundaries', '한계를 뛰어넘다', '경계를 밀다', '기존의 한계를 넘어 새로운 영역을 개척한다는 뜻이에요. 기술, 예술, 과학 모든 분야에서 써요.', 'This research team continues to push the boundaries of quantum computing.', '이 연구팀은 양자 컴퓨팅의 한계를 계속 뛰어넘고 있어요.', 'Their latest album pushes the boundaries of electronic music.', '그들의 최신 앨범은 일렉트로닉 음악의 한계를 뛰어넘어요.', 'We hire engineers who love to push the boundaries of what is possible.', '저희는 가능성의 한계를 뛰어넘기를 좋아하는 엔지니어를 채용해요.', 'C1', 'technology', 2, 'innovation lab', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_environment_C1_01', 'reduce', 'emissions', 'reduce emissions', '배출을 줄이다', 'lower', '''lower''도 가능하지만, 환경 정책에서는 ''reduce emissions''가 표준 표현이에요. 모든 기후 보고서에 등장해요.', 'The new policy aims to reduce emissions by 40 percent by 2030.', '새 정책은 2030년까지 배출량을 40퍼센트 줄이는 것을 목표로 해요.', 'Electric buses help cities reduce emissions in dense urban areas.', '전기 버스는 도시가 인구 밀집 지역의 배출을 줄이는 데 도움이 돼요.', 'C1', 'environment', 2, 'factory emissions'),
('col_environment_C1_02', 'protect', 'wildlife', 'protect wildlife', '야생동물을 보호하다', 'save', '''save''는 위급한 구조의 뉘앙스, ''protect''는 지속적인 보호 활동이라는 뜻이에요. 보전 정책에서는 ''protect''가 표준이에요.', 'National parks were established to protect wildlife and natural habitats.', '국립공원은 야생동물과 자연 서식지를 보호하기 위해 설립됐어요.', 'Stronger laws are needed to protect wildlife from illegal trade.', '야생동물을 불법 거래로부터 보호하려면 더 강력한 법이 필요해요.', 'C1', 'environment', 2, 'wildlife reserve'),
('col_environment_C1_03', 'tackle', 'pollution', 'tackle pollution', '오염에 대처하다', 'stop', '오염 문제를 체계적으로 다룬다는 정책 표현이에요. ''stop''은 너무 단순해서 신문이나 보고서에 안 어울려요.', 'The city launched a bold plan to tackle air pollution.', '시는 대기 오염에 대처하기 위해 과감한 계획을 시작했어요.', 'Tackling plastic pollution requires global cooperation.', '플라스틱 오염에 대처하려면 글로벌 협력이 필요해요.', 'C1', 'environment', 2, 'polluted river'),
('col_environment_C1_04', 'adopt', 'sustainable practices', 'adopt sustainable practices', '지속 가능한 관행을 도입하다', 'use', '회사나 개인이 친환경 방식을 받아들인다는 격식 표현이에요. ESG 보고서에 자주 나와요.', 'More farms are adopting sustainable practices to preserve soil health.', '더 많은 농장이 토양 건강을 지키기 위해 지속 가능한 관행을 도입하고 있어요.', 'Companies that adopt sustainable practices often see long-term cost savings.', '지속 가능한 관행을 도입하는 회사는 장기적으로 비용 절감 효과를 보는 경우가 많아요.', 'C1', 'environment', 2, 'sustainable farm'),
('col_environment_C1_05', 'raise', 'awareness', 'raise awareness', '인식을 높이다', 'tell', '캠페인을 통해 사회적 관심을 끌어올린다는 표준 표현이에요. 비영리, 정책, 마케팅 모두에서 써요.', 'The documentary helped raise awareness of declining bee populations.', '그 다큐멘터리는 감소하는 벌 개체수에 대한 인식을 높이는 데 기여했어요.', 'School programs raise awareness about recycling among young children.', '학교 프로그램은 어린이들 사이에서 재활용에 대한 인식을 높여요.', 'C1', 'environment', 2, 'environmental campaign')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_environment_C1_01', 'go green', '친환경적으로 바꾸다', '초록색이 되다', '생활이나 사업 방식을 친환경적으로 전환한다는 뜻이에요. 광고와 정책 캠페인에서 흔히 보여요.', 'Many small businesses are choosing to go green to attract eco-conscious customers.', '많은 소상공인이 친환경 의식이 있는 고객을 끌기 위해 친환경 전환을 선택하고 있어요.', 'Our office went green by switching to LED lighting and paperless workflows.', '저희 사무실은 LED 조명과 종이 없는 업무로 친환경 전환을 했어요.', 'Going green can also save money in the long run.', '친환경으로 전환하는 건 장기적으로 비용도 절약돼요.', 'C1', 'environment', 2, 'green leaves', 1),
('idm_environment_C1_02', 'carbon footprint', '탄소 발자국', '탄소 발자국', '개인이나 조직이 배출하는 온실가스의 총량을 가리켜요. ESG 보고서와 일상 대화 모두에서 표준이에요.', 'Flying less is one of the most effective ways to reduce your carbon footprint.', '비행을 줄이는 게 탄소 발자국을 줄이는 가장 효과적인 방법 중 하나예요.', 'The company published its carbon footprint for the first time this year.', '그 회사는 올해 처음으로 탄소 발자국을 공개했어요.', 'Eating locally grown food can lower your carbon footprint significantly.', '지역에서 생산된 음식을 먹으면 탄소 발자국을 크게 줄일 수 있어요.', 'C1', 'environment', 2, 'carbon footprint', 2),
('idm_environment_C1_03', 'tree-hugger', '환경운동가', '나무를 껴안는 사람', '환경 보호에 열성적인 사람을 가리키는 표현이에요. 때로 가볍게 비꼬는 뉘앙스가 있으니 친근한 자리에서 써요.', 'I used to think recycling was just for tree-huggers, but now I do it religiously.', '예전엔 재활용은 환경운동가들만 하는 거라 생각했지만, 지금은 철저히 하고 있어요.', 'He is not really a tree-hugger, but he cares deeply about clean water.', '그가 진짜 환경운동가는 아니지만, 깨끗한 물에 대해서는 깊이 신경 써요.', 'The brand is popular with tree-huggers and trend-followers alike.', '그 브랜드는 환경운동가와 유행을 따르는 사람 모두에게 인기가 있어요.', 'C1', 'environment', 2, 'tree hugging', 3),
('idm_environment_C1_04', 'a drop in the ocean', '새 발의 피', '바다의 물 한 방울', '필요한 양에 비해 너무 적은 양이라 큰 영향이 없다는 뜻이에요. 사회 문제나 정책 토론에 자주 등장해요.', 'Recycling one bottle is a drop in the ocean, but collective action matters.', '병 하나를 재활용하는 건 새 발의 피지만, 다 함께 행동하면 의미가 있어요.', 'The donation is appreciated, but it is a drop in the ocean compared to what is needed.', '기부는 감사하지만, 필요한 액수에 비하면 새 발의 피예요.', 'Individual efforts can feel like a drop in the ocean, yet they add up.', '개인의 노력은 새 발의 피처럼 느껴지지만, 모이면 커져요.', 'C1', 'environment', 2, 'water drop ocean', 4),
('idm_environment_C1_05', 'weather the storm', '난관을 견뎌내다', '폭풍을 견디다', '어려운 시기를 끝까지 버텨낸다는 뜻이에요. 기후 문제뿐 아니라 경제, 정치, 개인 일상에도 두루 써요.', 'Coastal communities have learned to weather the storm of increasingly extreme weather.', '해안 지역사회는 점점 극심해지는 기상의 난관을 견뎌내는 법을 배웠어요.', 'With careful planning, the firm weathered the storm of the recession.', '신중한 계획으로 그 회사는 불황의 난관을 견뎌냈어요.', 'We will weather the storm together as a team.', '우리는 한 팀으로 난관을 함께 견뎌낼 거예요.', 'C1', 'environment', 2, 'storm clouds', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_news_C1_01', 'cover', 'story', 'cover a story', '기사를 취재하다', 'write', '''write''는 단순 작성이지만, ''cover''는 취재·보도 전체 과정을 의미하는 저널리즘 표준 동사예요.', 'She has covered every major election story for the past decade.', '그녀는 지난 10년간 주요 선거 기사를 모두 취재해 왔어요.', 'Foreign correspondents cover stories from conflict zones around the world.', '해외 특파원들은 전 세계 분쟁 지역에서 기사를 취재해요.', 'C1', 'news', 2, 'journalist reporting'),
('col_news_C1_02', 'leak', 'information', 'leak information', '정보를 누설하다', 'tell', '비공개 정보를 외부에 흘린다는 정확한 동사예요. ''tell''은 너무 일반적이라 보도 맥락에 안 맞아요.', 'An anonymous source leaked information about the upcoming merger.', '익명의 소식통이 다가오는 합병에 대한 정보를 누설했어요.', 'Employees who leak information may face legal consequences.', '정보를 누설한 직원은 법적 처벌을 받을 수 있어요.', 'C1', 'news', 2, 'leaked documents'),
('col_news_C1_03', 'issue', 'statement', 'issue a statement', '성명을 발표하다', 'say', '공식 입장을 정식으로 발표한다는 격식 표현이에요. 기업이나 정부 발표 기사에서 표준이에요.', 'The minister issued a statement denying any wrongdoing.', '장관은 어떠한 잘못도 없다고 부인하는 성명을 발표했어요.', 'The studio issued a statement late last night about the casting change.', '스튜디오는 어젯밤 늦게 캐스팅 변경에 대한 성명을 발표했어요.', 'C1', 'news', 2, 'press release'),
('col_news_C1_04', 'hold', 'press conference', 'hold a press conference', '기자회견을 열다', 'make', '기자회견을 ''열다''는 ''hold''가 표준이에요. ''make''는 영어에서 어색해요.', 'The mayor will hold a press conference at noon to address the crisis.', '시장은 위기를 다루기 위해 정오에 기자회견을 열 거예요.', 'They held a press conference to announce the partnership.', '그들은 파트너십을 발표하기 위해 기자회견을 열었어요.', 'C1', 'news', 2, 'press conference'),
('col_news_C1_05', 'verify', 'sources', 'verify sources', '출처를 확인하다', 'check', '''check''도 통하지만, ''verify''가 저널리즘과 정보 검증에서 표준 동사예요. 팩트체크 보도의 핵심 표현이에요.', 'Responsible journalists always verify sources before publishing.', '책임감 있는 기자는 보도 전에 항상 출처를 확인해요.', 'In the age of social media, it is harder than ever to verify sources.', '소셜 미디어 시대에는 출처를 확인하기가 그 어느 때보다 어려워요.', 'C1', 'news', 2, 'fact checking')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_news_C1_01', 'breaking news', '속보', '깨지는 뉴스', '방금 들어온 중요한 뉴스를 가리켜요. TV 자막, 뉴스 헤드라인에서 항상 보이는 표준 표현이에요.', 'We interrupt this programme to bring you breaking news from the capital.', '수도에서 들어온 속보를 전해드리기 위해 방송을 중단합니다.', 'Breaking news alerts on my phone have become impossible to ignore.', '제 휴대폰의 속보 알림은 무시할 수 없게 됐어요.', 'The breaking news of the verdict spread across social media within minutes.', '평결 속보가 몇 분 만에 소셜 미디어 전반에 퍼졌어요.', 'C1', 'news', 2, 'breaking news banner', 1),
('idm_news_C1_02', 'in the headlines', '주요 뉴스에 오른', '헤드라인 안에 있는', '특정 주제가 언론의 주목을 받고 있다는 뜻이에요. 시사 토론과 보도 분석에서 자주 써요.', 'Climate change has been in the headlines all week following the new report.', '새 보고서 이후 기후 변화가 한 주 내내 주요 뉴스에 올라 있어요.', 'The scandal kept the senator in the headlines for months.', '그 스캔들로 그 상원의원은 몇 달간 주요 뉴스에 올랐어요.', 'Tech layoffs are back in the headlines this morning.', '오늘 아침 테크업계 정리해고가 다시 주요 뉴스에 올랐어요.', 'C1', 'news', 2, 'newspaper headlines', 2),
('idm_news_C1_03', 'off the record', '비보도를 전제로', '기록 밖에서', '말한 내용이 보도되지 않는 조건으로 한다는 저널리즘 용어예요. 인터뷰 협상에서 자주 등장해요.', 'Off the record, the official admitted that negotiations had stalled.', '비보도를 전제로, 그 관리는 협상이 교착 상태에 빠졌다고 인정했어요.', 'Can I tell you something off the record? I do not want this in your article.', '비보도를 전제로 하나 말해도 될까요? 기사에 나가지 않았으면 해요.', 'Several sources spoke off the record about internal disagreements.', '여러 소식통이 내부 갈등에 대해 비보도를 전제로 말했어요.', 'C1', 'news', 2, 'private interview', 3),
('idm_news_C1_04', 'scoop a story', '특종을 잡다', '이야기를 퍼올리다', '경쟁사보다 먼저 중요한 기사를 보도한다는 저널리즘 표현이에요. 명사 ''scoop''으로도 자주 써요.', 'The young reporter scooped the story of the year on her very first assignment.', '그 신입 기자는 첫 임무에서 올해의 특종을 잡았어요.', 'Independent outlets often scoop stories that big newspapers miss.', '독립 매체들은 대형 신문이 놓치는 기사를 종종 특종으로 잡아요.', 'They scooped the story by interviewing the whistleblower first.', '그들은 내부 고발자를 먼저 인터뷰해서 특종을 잡았어요.', 'C1', 'news', 2, 'reporter notebook', 4),
('idm_news_C1_05', 'a hot topic', '화제거리', '뜨거운 주제', '많은 사람들이 활발히 논의하고 있는 주제를 뜻해요. 토크쇼, 칼럼, 일상 대화 모두에서 자연스럽게 써요.', 'Artificial intelligence regulation has become a hot topic in policy circles.', '인공지능 규제는 정책 분야에서 화제거리가 됐어요.', 'Housing affordability is a hot topic ahead of the local elections.', '주거 비용 부담은 지방선거를 앞두고 화제거리예요.', 'Remote work remains a hot topic among HR professionals.', '원격 근무는 인사 담당자들 사이에서 여전히 화제거리예요.', 'C1', 'news', 2, 'discussion panel', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_sports_C1_01', 'win', 'match', 'win a match', '경기에서 이기다', 'beat', '''beat''는 상대를 이기는 것, ''win a match''는 시합 자체를 이긴다는 뜻이라 미묘하게 달라요. 경기 결과 표현의 기본이에요.', 'They need to win the next match to qualify for the finals.', '그들이 결승에 진출하려면 다음 경기에서 이겨야 해요.', 'She has won every match in straight sets this tournament.', '그녀는 이번 토너먼트에서 모든 경기를 스트레이트 세트로 이겼어요.', 'C1', 'sports', 2, 'tennis match'),
('col_sports_C1_02', 'make', 'comeback', 'make a comeback', '재기하다', 'do', '부진이나 부상 후 다시 활약한다는 표준 표현이에요. ''do a comeback''은 영어에서 어색해요.', 'The veteran striker is hoping to make a comeback next season.', '그 베테랑 공격수는 다음 시즌에 재기하기를 바라고 있어요.', 'After two surgeries, she made a remarkable comeback at the Olympics.', '두 차례 수술 후 그녀는 올림픽에서 놀라운 재기를 이뤄냈어요.', 'C1', 'sports', 2, 'athlete returning'),
('col_sports_C1_03', 'set', 'record', 'set a record', '기록을 세우다', 'make', '새로운 최고 기록을 만든다는 표준 동사 조합이에요. ''make a record''는 음반 만들 때 써서 헷갈리기 쉬워요.', 'He set a world record in the 200 meters at last summer''s championships.', '그는 지난여름 챔피언십에서 200미터 세계 기록을 세웠어요.', 'The team set a new club record for consecutive wins.', '그 팀은 연승 부문에서 새로운 구단 기록을 세웠어요.', 'C1', 'sports', 2, 'stadium record'),
('col_sports_C1_04', 'score', 'goal', 'score a goal', '골을 넣다', 'make', '축구, 하키 등에서 득점한다는 가장 기본적이고 정확한 동사예요. ''make a goal''은 어색해요.', 'He scored a stunning goal from outside the penalty box.', '그는 페널티 박스 밖에서 멋진 골을 넣었어요.', 'She has scored a goal in every match this season.', '그녀는 이번 시즌 모든 경기에서 골을 넣었어요.', 'C1', 'sports', 2, 'soccer goal'),
('col_sports_C1_05', 'claim', 'victory', 'claim victory', '승리를 거머쥐다', 'get', '경쟁 후 승리를 공식적으로 차지한다는 격식 있는 표현이에요. 스포츠 헤드라인의 단골이에요.', 'The underdogs claimed victory after a thrilling penalty shootout.', '약체 팀이 짜릿한 승부차기 끝에 승리를 거머쥐었어요.', 'She claimed victory in her debut tournament with surprising ease.', '그녀는 데뷔 토너먼트에서 의외로 수월하게 승리를 거머쥐었어요.', 'C1', 'sports', 2, 'victory celebration')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_sports_C1_01', 'level the playing field', '공평한 조건을 만들다', '경기장을 평평하게 하다', '모두에게 동등한 기회를 만든다는 뜻이에요. 스포츠뿐 아니라 비즈니스, 정책 토론에서도 자주 써요.', 'Salary caps were introduced to level the playing field between rich and small-market clubs.', '연봉 상한제는 부유한 구단과 소형 시장 구단 사이의 공평한 조건을 만들기 위해 도입됐어요.', 'New regulations aim to level the playing field for small startups.', '새 규제는 작은 스타트업에게 공평한 조건을 만들어주기 위한 거예요.', 'Scholarships help level the playing field for talented athletes from any background.', '장학금은 어떤 배경의 재능 있는 선수에게도 공평한 조건을 만들어줘요.', 'C1', 'sports', 2, 'soccer field', 1),
('idm_sports_C1_02', 'in the running', '유력 후보인', '달리기 안에 있는', '경쟁이나 선발에서 아직 유력한 후보 자리에 있다는 뜻이에요. 스포츠, 채용, 시상 등 폭넓게 써요.', 'Three teams are still in the running for the championship title.', '세 팀이 아직 우승 타이틀의 유력 후보로 남아 있어요.', 'She is in the running for the head coach position next season.', '그녀는 다음 시즌 수석 코치직의 유력 후보예요.', 'After this round, only two candidates remain in the running.', '이번 라운드 후 단 두 후보만 유력 후보로 남아 있어요.', 'C1', 'sports', 2, 'race competitors', 2),
('idm_sports_C1_03', 'down to the wire', '끝까지 가는 접전', '와이어 끝까지', '결과가 마지막 순간까지 결정되지 않는 접전이라는 뜻이에요. 스포츠 중계와 선거 보도 모두에서 자주 들려요.', 'The marathon went down to the wire, with the winner deciding it in the final 100 metres.', '마라톤은 끝까지 가는 접전이었고, 우승은 마지막 100미터에서 결정됐어요.', 'Negotiations went down to the wire before the deadline expired.', '협상은 마감 만료 직전까지 가는 접전이었어요.', 'Both teams are evenly matched — this will go down to the wire.', '두 팀이 막상막하예요. 끝까지 가는 접전이 될 거예요.', 'C1', 'sports', 2, 'finish line', 3),
('idm_sports_C1_04', 'on the ropes', '궁지에 몰린', '로프에 몰린', '권투에서 유래한 표현으로, 패배 직전의 위기 상황을 가리켜요. 스포츠와 비즈니스에서 모두 써요.', 'The defending champion was on the ropes after losing two consecutive sets.', '디펜딩 챔피언이 두 세트 연속 패배 후 궁지에 몰렸어요.', 'The startup was on the ropes until a last-minute investor stepped in.', '그 스타트업은 막판에 투자자가 등장하기 전까지 궁지에 몰려 있었어요.', 'Critics suggest the manager is on the ropes after another disappointing result.', '비평가들은 또 다른 실망스러운 결과 후 그 감독이 궁지에 몰렸다고 봐요.', 'C1', 'sports', 2, 'boxing ring', 4),
('idm_sports_C1_05', 'the home stretch', '막바지', '집까지의 마지막 직선 구간', '경마에서 유래한 표현으로, 일이나 시즌의 마지막 단계를 뜻해요. 스포츠뿐 아니라 프로젝트 마감에도 자주 써요.', 'We are in the home stretch of the regular season, with playoffs just weeks away.', '플레이오프가 불과 몇 주 앞이고, 정규 시즌의 막바지에 와 있어요.', 'The project is in the home stretch — just one more week of testing left.', '프로젝트는 막바지예요. 테스트가 일주일만 남았어요.', 'Athletes often peak as they enter the home stretch of training.', '선수들은 훈련의 막바지에 들어설 때 최고조에 이르는 경우가 많아요.', 'C1', 'sports', 2, 'race finish line', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_emotion_C1_01', 'vent', 'frustration', 'vent frustration', '답답함을 토로하다', 'say', '쌓인 부정적 감정을 말이나 행동으로 풀어낸다는 뜻이에요. 직장 상담이나 인터뷰에서 자주 쓰는 격식 표현이에요.', 'She needed a trusted colleague to vent her frustration after the meeting.', '그녀는 회의 후 답답함을 토로할 믿을 만한 동료가 필요했어요.', 'Employees often vent their frustration in anonymous surveys.', '직원들은 익명 설문에서 답답함을 토로하곤 해요.', 'C1', 'emotion', 2, 'person venting'),
('col_emotion_C1_02', 'express', 'gratitude', 'express gratitude', '감사를 표하다', 'say', '감사한 마음을 격식 있게 전한다는 뜻이에요. ''say thanks''보다 훨씬 정중하고 글쓰기에서 표준 표현이에요.', 'He took a moment to express his gratitude to the entire research team.', '그는 잠시 시간을 내어 연구팀 전체에 감사를 표했어요.', 'In her acceptance speech, she expressed gratitude to her mentors.', '수상 소감에서 그녀는 멘토들에게 감사를 표했어요.', 'C1', 'emotion', 2, 'thank you note'),
('col_emotion_C1_03', 'hide', 'disappointment', 'hide disappointment', '실망감을 감추다', 'cover', '속으로는 실망했지만 겉으로는 드러내지 않으려 한다는 뜻이에요. 인터뷰, 협상, 가족 대화에서 자주 보여요.', 'She tried to hide her disappointment when the promotion went to someone else.', '승진이 다른 사람에게 갔을 때 그녀는 실망감을 감추려 했어요.', 'He could barely hide his disappointment at the verdict.', '그는 판결에 대한 실망감을 거의 감추지 못했어요.', 'C1', 'emotion', 2, 'sad face'),
('col_emotion_C1_04', 'show', 'empathy', 'show empathy', '공감을 보이다', 'feel', '단순히 느끼는 것을 넘어 상대에게 공감하는 태도를 드러낸다는 뜻이에요. 리더십, 상담, 의료 현장에서 핵심 표현이에요.', 'Effective managers show empathy without losing their professional edge.', '유능한 관리자는 전문성을 잃지 않으면서 공감을 보여요.', 'Nurses are trained to show empathy under stressful conditions.', '간호사들은 스트레스 상황에서도 공감을 보이도록 훈련받아요.', 'C1', 'emotion', 2, 'caring conversation'),
('col_emotion_C1_05', 'bottle up', 'emotions', 'bottle up emotions', '감정을 억누르다', 'keep', '감정을 표현하지 않고 속에 쌓아둔다는 뜻이에요. 심리학, 자기계발 글에서 표준으로 쓰는 표현이에요.', 'Bottling up your emotions for years can take a serious toll on your health.', '수년간 감정을 억누르면 건강에 큰 타격을 줄 수 있어요.', 'He has a tendency to bottle up his emotions instead of talking them through.', '그는 감정을 털어놓기보다 억누르는 경향이 있어요.', 'C1', 'emotion', 2, 'bottle silhouette')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_emotion_C1_01', 'wear your heart on your sleeve', '감정을 숨김없이 드러내다', '심장을 소매 위에 달다', '자기 감정을 솔직하게 다 보여준다는 뜻이에요. 칭찬과 비판 모두 가능하니 상황에 맞게 써야 해요.', 'She wears her heart on her sleeve, which makes her a wonderfully sincere friend.', '그녀는 감정을 숨김없이 드러내는데, 그래서 정말 진솔한 친구예요.', 'In leadership, wearing your heart on your sleeve can be both a strength and a vulnerability.', '리더십에서 감정을 그대로 드러내는 건 강점이자 약점이 될 수 있어요.', 'He is not the type to wear his heart on his sleeve at work.', '그는 직장에서 감정을 그대로 드러내는 타입은 아니에요.', 'C1', 'emotion', 2, 'heart sleeve', 1),
('idm_emotion_C1_02', 'have a heart of gold', '마음이 따뜻하다', '황금의 심장을 가지다', '겉모습과 상관없이 본성이 한없이 친절하고 너그럽다는 뜻이에요. 사람을 칭찬할 때 격식 자리에서도 자연스러워요.', 'Despite his gruff exterior, he has a heart of gold.', '그는 무뚝뚝해 보이지만 마음이 따뜻해요.', 'My grandmother had a heart of gold and never turned anyone away.', '저희 할머니는 마음이 따뜻해서 누구도 외면하지 않으셨어요.', 'Volunteers with a heart of gold sustain the entire organization.', '마음이 따뜻한 자원봉사자들이 조직 전체를 지탱해요.', 'C1', 'emotion', 2, 'gold heart', 2),
('idm_emotion_C1_03', 'head over heels', '푹 빠지다', '머리가 발꿈치 위로', '주로 사랑에 완전히 빠진 상태를 가리키는 표현이에요. 일이나 취미에 푹 빠졌다고 비유적으로도 써요.', 'They have been head over heels in love since their college years.', '그들은 대학 시절부터 서로에게 푹 빠져 있어요.', 'She fell head over heels for the city of Lisbon during her sabbatical.', '그녀는 안식년 동안 리스본이라는 도시에 푹 빠졌어요.', 'He is head over heels about his new research topic.', '그는 새 연구 주제에 푹 빠져 있어요.', 'C1', 'emotion', 2, 'couple in love', 3),
('idm_emotion_C1_04', 'down in the dumps', '의기소침하다', '쓰레기 더미 안에 있는', '특별한 이유 없이 우울하거나 기운이 없다는 뜻이에요. 친한 동료나 가족과의 대화에서 자연스럽게 써요.', 'He has been down in the dumps ever since the project was cancelled.', '그는 그 프로젝트가 취소된 이후 계속 의기소침해 있어요.', 'Rainy weeks always leave her down in the dumps.', '비가 오는 주가 길어지면 그녀는 항상 의기소침해져요.', 'Why are you so down in the dumps today?', '오늘 왜 그렇게 기운이 없어요?', 'C1', 'emotion', 2, 'gloomy person', 4),
('idm_emotion_C1_05', 'on cloud nine', '하늘을 날 듯 기쁘다', '아홉 번째 구름 위에', '아주 행복하고 신이 난 상태를 묘사하는 표현이에요. 좋은 소식을 전할 때 격식과 비격식 모두에서 자연스러워요.', 'She has been on cloud nine since her paper was accepted by the journal.', '논문이 학술지에 채택된 이후 그녀는 하늘을 날 듯 기뻐하고 있어요.', 'After the engagement, they were both on cloud nine.', '약혼 후 두 사람은 모두 하늘을 날 듯 기뻤어요.', 'Winning the contract put the whole team on cloud nine.', '계약을 따낸 일로 팀 전체가 하늘을 날 듯 기뻐했어요.', 'C1', 'emotion', 2, 'clouds sky', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_culture_C1_01', 'embrace', 'diversity', 'embrace diversity', '다양성을 포용하다', 'accept', '단순히 받아들이는 것이 아니라 적극적으로 환영하고 가치를 둔다는 뜻이에요. 조직 가치 선언문에 자주 등장해요.', 'The university actively embraces diversity in its student body and faculty.', '그 대학은 학생과 교수진의 다양성을 적극적으로 포용해요.', 'Modern workplaces must embrace diversity to remain competitive.', '현대 직장은 경쟁력을 유지하려면 다양성을 포용해야 해요.', 'C1', 'culture', 2, 'diverse group'),
('col_culture_C1_02', 'preserve', 'heritage', 'preserve heritage', '유산을 보존하다', 'keep', '문화적, 역사적 가치를 후대에 전하기 위해 지킨다는 격식 표현이에요. UNESCO 문서에서 표준이에요.', 'The foundation works tirelessly to preserve the heritage of indigenous communities.', '그 재단은 원주민 공동체의 유산을 보존하기 위해 끊임없이 노력해요.', 'Local artisans help preserve a heritage that spans generations.', '지역 장인들은 여러 세대에 걸친 유산을 보존하는 데 기여해요.', 'C1', 'culture', 2, 'historic building'),
('col_culture_C1_03', 'challenge', 'stereotypes', 'challenge stereotypes', '고정관념에 도전하다', 'change', '기존의 편견이나 고정관념에 정면으로 맞선다는 뜻이에요. 사회 비평, 광고 캠페인에서 자주 보여요.', 'Her documentary boldly challenges stereotypes about rural communities.', '그녀의 다큐멘터리는 농촌 공동체에 대한 고정관념에 과감히 도전해요.', 'The campaign was designed to challenge stereotypes about ageing.', '그 캠페인은 노화에 대한 고정관념에 도전하기 위해 기획됐어요.', 'C1', 'culture', 2, 'breaking barriers'),
('col_culture_C1_04', 'appreciate', 'art', 'appreciate art', '예술을 감상하다', 'like', '단순한 호감을 넘어 가치를 이해하며 감상한다는 격식 표현이에요. 미술관 안내문이나 평론에 어울려요.', 'Learning to appreciate art often begins with understanding its historical context.', '예술을 감상하는 법은 보통 그 역사적 맥락을 이해하는 데서 시작해요.', 'She has cultivated an ability to appreciate art across many periods.', '그녀는 다양한 시대의 예술을 감상할 수 있는 안목을 길렀어요.', 'C1', 'culture', 2, 'art gallery'),
('col_culture_C1_05', 'celebrate', 'traditions', 'celebrate traditions', '전통을 기리다', 'do', '문화 전통을 의식적으로 기념하고 가치를 인정한다는 뜻이에요. 명절, 축제 보도에서 표준 표현이에요.', 'The festival celebrates the traditions of the Andean highlands.', '그 축제는 안데스 고원의 전통을 기려요.', 'Families gather every autumn to celebrate the traditions of Chuseok.', '가족들은 매년 가을 추석의 전통을 기리기 위해 모여요.', 'C1', 'culture', 2, 'traditional festival')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_culture_C1_01', 'when in Rome', '로마에서는 로마법을 따르라', '로마에 있을 때는', '낯선 곳에 가면 그곳의 관습을 따르라는 뜻이에요. 격식 자리에서도 자연스럽게 쓰는 고전적 표현이에요.', 'I do not usually eat raw fish, but when in Rome.', '저는 보통 회를 먹지 않지만, 로마에서는 로마법을 따라야죠.', 'She bowed deeply at the meeting — when in Rome, after all.', '그녀는 회의에서 깊이 인사했어요. 로마에서는 로마법을 따라야 하니까요.', 'When in Rome, you take off your shoes before entering a Korean home.', '한국 가정에 들어갈 때는 신발을 벗어야 해요. 그게 그곳의 법이니까요.', 'C1', 'culture', 2, 'rome colosseum', 1),
('idm_culture_C1_02', 'a melting pot', '여러 문화가 섞인 곳', '녹는 냄비', '다양한 인종, 문화, 배경이 한곳에 어우러진 공간을 가리켜요. 도시나 국가를 설명하는 격식 표현이에요.', 'New York has long been described as a melting pot of cultures.', '뉴욕은 오랫동안 여러 문화가 섞인 곳으로 묘사돼 왔어요.', 'The campus is a true melting pot, with students from over eighty countries.', '그 캠퍼스는 80개국 이상에서 온 학생들로 이루어진 진정한 용광로예요.', 'Their neighbourhood became a melting pot after the 1990s.', '그들의 동네는 1990년대 이후 여러 문화가 섞인 곳이 됐어요.', 'C1', 'culture', 2, 'diverse city', 2),
('idm_culture_C1_03', 'a cultural icon', '문화적 상징', '문화적 우상', '특정 문화나 시대를 대표하는 인물이나 작품을 가리켜요. 평론, 부고, 인터뷰에서 표준 표현이에요.', 'Audrey Hepburn remains a cultural icon decades after her death.', '오드리 헵번은 사후 수십 년이 지난 지금도 문화적 상징으로 남아 있어요.', 'The film quickly became a cultural icon of the 1980s.', '그 영화는 1980년대의 문화적 상징이 됐어요.', 'For many Koreans, that drama is now a cultural icon.', '많은 한국인에게 그 드라마는 이제 문화적 상징이에요.', 'C1', 'culture', 2, 'famous portrait', 3),
('idm_culture_C1_04', 'stand the test of time', '세월의 시험을 견디다', '시간의 시험을 견디다', '오랜 시간이 지나도 가치나 인기가 유지된다는 뜻이에요. 예술, 디자인, 사상 평론에서 자주 써요.', 'Few literary works truly stand the test of time.', '진정으로 세월의 시험을 견디는 문학 작품은 드물어요.', 'Their minimalist design has stood the test of time.', '그들의 미니멀한 디자인은 세월의 시험을 견뎌왔어요.', 'Whether this trend will stand the test of time remains to be seen.', '이 트렌드가 세월을 견딜지는 두고 봐야 해요.', 'C1', 'culture', 2, 'old monument', 4),
('idm_culture_C1_05', 'lost in translation', '번역 과정에서 의미가 사라진', '번역 안에서 길을 잃은', '한 언어에서 다른 언어로 옮기는 과정에서 미묘한 의미가 빠진다는 뜻이에요. 비유적으로 문화 간 소통에서도 자주 써요.', 'Much of the original poem''s rhythm is lost in translation.', '그 시 원작의 운율은 번역 과정에서 많이 사라져요.', 'His joke seemed to get lost in translation during the keynote.', '기조 연설에서 그의 농담은 번역 과정에서 의미가 사라진 듯했어요.', 'Subtle cultural cues are often lost in translation.', '미묘한 문화적 단서는 번역 과정에서 종종 사라져요.', 'C1', 'culture', 2, 'translation books', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_humanities_C1_01', 'explore', 'themes', 'explore themes', '주제를 탐구하다', 'see', '문학, 영화, 예술 작품의 주제를 깊이 파헤친다는 격식 표현이에요. 비평이나 학술 글의 표준이에요.', 'The novel explores themes of memory, loss, and identity.', '그 소설은 기억, 상실, 정체성이라는 주제를 탐구해요.', 'Her latest essay explores themes that recur throughout postwar literature.', '그녀의 최신 에세이는 전후 문학 전반에 반복되는 주제를 탐구해요.', 'C1', 'humanities', 2, 'open book'),
('col_humanities_C1_02', 'analyze', 'texts', 'analyze texts', '텍스트를 분석하다', 'read', '텍스트의 구조, 의미, 맥락을 비판적으로 살핀다는 학문적 표현이에요. 인문학 강의실의 핵심 동사예요.', 'Students learn to analyze texts using a range of critical frameworks.', '학생들은 다양한 비평 틀을 활용해 텍스트를 분석하는 법을 배워요.', 'She analyzed the texts side by side to trace the author''s evolution.', '그녀는 작가의 변천을 추적하기 위해 텍스트들을 나란히 분석했어요.', 'C1', 'humanities', 2, 'literary analysis'),
('col_humanities_C1_03', 'trace', 'origins', 'trace the origins', '기원을 추적하다', 'find', '어떤 개념이나 관습의 역사적 출처를 거슬러 올라간다는 뜻이에요. 역사학, 어원학에서 자주 써요.', 'The book traces the origins of modern democracy to ancient Athens.', '그 책은 현대 민주주의의 기원을 고대 아테네까지 추적해요.', 'Linguists trace the origins of the word to a medieval Latin root.', '언어학자들은 그 단어의 기원을 중세 라틴어 어근까지 추적해요.', 'C1', 'humanities', 2, 'ancient ruins'),
('col_humanities_C1_04', 'draw', 'parallels', 'draw parallels', '유사점을 끌어내다', 'find', '서로 다른 두 가지 사이의 닮은 점을 짚어낸다는 격식 표현이에요. 비교 분석 글에서 표준이에요.', 'The essay draws parallels between Roman and modern American politics.', '그 에세이는 로마와 현대 미국 정치 사이의 유사점을 끌어내요.', 'Critics have drawn parallels between the two filmmakers'' visual styles.', '비평가들은 두 영화감독의 시각적 스타일 사이에서 유사점을 끌어냈어요.', 'C1', 'humanities', 2, 'parallel lines'),
('col_humanities_C1_05', 'challenge', 'interpretations', 'challenge interpretations', '해석에 이의를 제기하다', 'change', '기존의 학설이나 해석에 비판적으로 도전한다는 뜻이에요. 학술 논문 서론에서 자주 보이는 표현이에요.', 'Her dissertation challenges long-standing interpretations of the text.', '그녀의 박사 논문은 그 텍스트에 대한 오랜 해석에 이의를 제기해요.', 'Newly discovered manuscripts have challenged earlier interpretations of the war.', '새로 발견된 사본들은 그 전쟁에 대한 기존 해석에 이의를 제기해 왔어요.', 'C1', 'humanities', 2, 'manuscript study')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_humanities_C1_01', 'ivory tower', '상아탑', '상아로 된 탑', '현실과 동떨어진 학문 세계나 사람을 비유하는 표현이에요. 학계 비판이나 자조적 농담에 자주 써요.', 'Critics accuse the professor of writing from an ivory tower.', '비평가들은 그 교수가 상아탑에서 글을 쓴다고 비판해요.', 'Policy must connect with practice, not remain in the ivory tower.', '정책은 상아탑에 머물지 말고 현장과 연결돼야 해요.', 'She left the ivory tower to work in community education.', '그녀는 상아탑을 떠나 지역사회 교육 분야로 옮겼어요.', 'C1', 'humanities', 2, 'university tower', 1),
('idm_humanities_C1_02', 'food for thought', '생각할 거리', '생각을 위한 음식', '곱씹어 볼 만한 흥미로운 주제나 의견을 가리키는 표현이에요. 강연, 토론 후기에 자연스럽게 써요.', 'His closing remarks gave us plenty of food for thought.', '그의 마무리 발언은 우리에게 생각할 거리를 많이 줬어요.', 'The article offers genuine food for thought on the future of higher education.', '그 기사는 고등교육의 미래에 대해 진정한 생각할 거리를 제공해요.', 'Here is some food for thought before our next meeting.', '다음 회의 전에 생각해 볼 거리를 좀 드릴게요.', 'C1', 'humanities', 2, 'thinking person', 2),
('idm_humanities_C1_03', 'in a nutshell', '한마디로 말하면', '견과 껍데기 안에', '복잡한 내용을 아주 간결하게 요약할 때 쓰는 표현이에요. 발표, 보고서, 학술 대화에서 모두 자연스러워요.', 'In a nutshell, the author argues that language shapes thought.', '한마디로 말하면, 저자는 언어가 사고를 형성한다고 주장해요.', 'The reform, in a nutshell, prioritizes accessibility over prestige.', '그 개혁은 한마디로 명성보다 접근성을 우선시해요.', 'In a nutshell, we need more time and more data.', '한마디로 우리는 더 많은 시간과 데이터가 필요해요.', 'C1', 'humanities', 2, 'walnut shell', 3),
('idm_humanities_C1_04', 'the gist of it', '요지', '그것의 핵심', '글이나 말의 핵심 뜻을 가리키는 표현이에요. 회의에서 ''요점은 이거예요''라고 정리할 때 자주 써요.', 'I have not read the full report, but I got the gist of it.', '보고서를 다 읽지는 않았지만, 요지는 파악했어요.', 'Could you give me the gist of it before the call?', '통화 전에 요지만 간단히 알려 주실 수 있어요?', 'The gist of it is that we need to revise our approach.', '요지는 우리가 접근 방식을 수정해야 한다는 거예요.', 'C1', 'humanities', 2, 'summary notes', 4),
('idm_humanities_C1_05', 'to make a long story short', '간단히 말하자면', '긴 이야기를 짧게 만들자면', '복잡한 배경 설명을 건너뛰고 결론으로 바로 가겠다는 신호예요. 회의나 발표 도입부에 자주 써요.', 'To make a long story short, the experiment ultimately succeeded.', '간단히 말하자면, 그 실험은 결국 성공했어요.', 'To make a long story short, the merger was called off at the last minute.', '간단히 말하자면, 그 합병은 막판에 무산됐어요.', 'To make a long story short, we are going back to the original design.', '간단히 말하자면, 우리는 원래 디자인으로 돌아가요.', 'C1', 'humanities', 2, 'long scroll', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_presentation_C1_01', 'deliver', 'speech', 'deliver a speech', '연설을 하다', 'say', '준비된 연설을 청중 앞에서 전달한다는 격식 표현이에요. ''give''도 가능하지만 ''deliver''가 더 전문적이에요.', 'She delivered a powerful keynote speech at the global summit.', '그녀는 글로벌 정상회의에서 강력한 기조연설을 했어요.', 'He has been invited to deliver a commencement speech at his alma mater.', '그는 모교에서 졸업 연설을 해 달라는 초청을 받았어요.', 'C1', 'presentation', 2, 'speaker podium'),
('col_presentation_C1_02', 'engage', 'audience', 'engage the audience', '청중을 사로잡다', 'interest', '청중의 주의를 끌고 적극적으로 참여시킨다는 뜻이에요. 발표 코칭에서 가장 자주 쓰는 표현 중 하나예요.', 'A great presenter knows how to engage the audience from the first slide.', '훌륭한 발표자는 첫 슬라이드부터 청중을 사로잡는 법을 알아요.', 'She engaged the audience by opening with a personal story.', '그녀는 개인적인 이야기로 시작하며 청중을 사로잡았어요.', 'C1', 'presentation', 2, 'engaged crowd'),
('col_presentation_C1_03', 'highlight', 'key points', 'highlight key points', '핵심을 강조하다', 'show', '발표나 글의 중요한 부분을 두드러지게 보여준다는 뜻이에요. 비즈니스 미팅과 학회 발표에서 표준이에요.', 'Let me highlight the key points before we open the floor for questions.', '질의응답을 열기 전에 핵심을 강조해 드릴게요.', 'The executive summary highlights the key points of the report.', '요약본은 보고서의 핵심을 강조해요.', 'C1', 'presentation', 2, 'highlighted text'),
('col_presentation_C1_04', 'field', 'question', 'field a question', '질문에 답하다', 'answer', '청중의 질문을 능숙하게 받아 답한다는 격식 표현이에요. 기자회견과 Q&A 세션에서 표준이에요.', 'The CEO fielded a difficult question about layoffs with composure.', 'CEO는 정리해고에 대한 까다로운 질문에 침착하게 답했어요.', 'She skillfully fielded questions from skeptical investors.', '그녀는 회의적인 투자자들의 질문에 능숙하게 답했어요.', 'C1', 'presentation', 2, 'press conference'),
('col_presentation_C1_05', 'wrap up', 'talk', 'wrap up a talk', '발표를 마무리하다', 'finish', '발표나 강연을 깔끔하게 마무리한다는 뜻이에요. 격식 자리에서도 자연스러운 비즈니스 표현이에요.', 'Let me wrap up this talk with three actionable takeaways.', '실행 가능한 시사점 세 가지로 이 발표를 마무리할게요.', 'She wrapped up her talk by inviting the audience to continue the conversation online.', '그녀는 청중에게 온라인에서 대화를 이어가자고 제안하며 발표를 마무리했어요.', 'C1', 'presentation', 2, 'closing slide')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_presentation_C1_01', 'break the ice', '어색한 분위기를 풀다', '얼음을 깨다', '처음 만난 사람들 사이의 어색함을 없애기 위해 가볍게 시작한다는 뜻이에요. 발표나 워크숍 오프닝의 핵심 표현이에요.', 'She broke the ice with a witty anecdote about her morning commute.', '그녀는 출근길 일화로 재치 있게 어색한 분위기를 풀었어요.', 'A quick poll is a useful way to break the ice with a new audience.', '간단한 설문은 새 청중과의 어색한 분위기를 푸는 좋은 방법이에요.', 'He broke the ice by asking everyone to introduce themselves in one word.', '그는 모두에게 한 단어로 자기소개를 하라며 어색한 분위기를 풀었어요.', 'C1', 'presentation', 2, 'ice breaking', 1),
('idm_presentation_C1_02', 'get to the point', '본론으로 들어가다', '요점에 도달하다', '잡담이나 빙빙 도는 설명을 그만두고 핵심으로 가자는 뜻이에요. 회의를 효율적으로 진행할 때 자주 써요.', 'We are short on time, so let me get to the point.', '시간이 부족하니 본론으로 바로 들어갈게요.', 'Could you get to the point? We need a decision by noon.', '본론으로 들어가 주실래요? 정오까지 결정해야 해요.', 'A good presenter gets to the point within the first two minutes.', '훌륭한 발표자는 첫 2분 안에 본론으로 들어가요.', 'C1', 'presentation', 2, 'arrow target', 2),
('idm_presentation_C1_03', 'think on your feet', '즉석에서 대응하다', '발 위에서 생각하다', '준비되지 않은 상황에서도 빠르고 유연하게 대처한다는 뜻이에요. 면접, 협상, Q&A에서 핵심 역량이에요.', 'A skilled moderator has to think on their feet during live Q&A.', '능숙한 사회자는 라이브 Q&A에서 즉석에서 대응할 줄 알아야 해요.', 'She thinks on her feet better than anyone I have worked with.', '그녀는 제가 함께 일해 본 누구보다 즉석 대응을 잘해요.', 'Sales reps are trained to think on their feet under pressure.', '영업 직원들은 압박 속에서 즉석 대응하도록 훈련받아요.', 'C1', 'presentation', 2, 'quick response', 3),
('idm_presentation_C1_04', 'cut to the chase', '핵심으로 바로 가다', '추격 장면으로 자르다', '서두를 건너뛰고 결론이나 본론으로 바로 가자는 뜻이에요. ''get to the point''보다 약간 더 단호한 뉘앙스예요.', 'Let me cut to the chase: we need to rethink the launch date.', '핵심으로 바로 갈게요. 출시일을 다시 생각해야 해요.', 'Investors appreciate it when founders cut to the chase.', '투자자들은 창업자가 핵심으로 바로 가는 것을 좋아해요.', 'Cutting to the chase, the proposal lacks a clear budget.', '핵심으로 가자면, 그 제안서에는 명확한 예산이 없어요.', 'C1', 'presentation', 2, 'fast motion', 4),
('idm_presentation_C1_05', 'lay it on the line', '솔직하게 말하다', '그것을 선 위에 놓다', '주저하지 않고 분명하고 솔직하게 의견이나 사실을 밝힌다는 뜻이에요. 진솔한 피드백이나 경고 자리에 어울려요.', 'Let me lay it on the line — the current strategy is not working.', '솔직하게 말씀드릴게요. 현재 전략은 효과가 없어요.', 'She laid it on the line during the performance review.', '그녀는 성과 평가에서 솔직하게 말했어요.', 'It is time to lay it on the line with the client about the delay.', '지연에 대해 고객에게 솔직히 말할 때예요.', 'C1', 'presentation', 2, 'honest conversation', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_greeting_C1_01', 'exchange', 'pleasantries', 'exchange pleasantries', '인사말을 주고받다', 'say', '본론에 들어가기 전에 격식 있는 가벼운 인사말을 주고받는다는 뜻이에요. 비즈니스 미팅 도입부 표준 표현이에요.', 'The two delegations exchanged pleasantries before the negotiations began.', '두 대표단은 협상이 시작되기 전에 인사말을 주고받았어요.', 'After exchanging pleasantries, we got straight to the agenda.', '인사말을 주고받은 뒤 우리는 곧바로 안건으로 들어갔어요.', 'C1', 'greeting', 2, 'handshake meeting'),
('col_greeting_C1_02', 'make', 'small talk', 'make small talk', '잡담을 나누다', 'do', '날씨나 가벼운 주제로 짧게 대화한다는 뜻이에요. 네트워킹 자리에서 가장 자주 쓰는 격식 표현이에요.', 'He is excellent at making small talk with clients before formal meetings.', '그는 공식 회의 전에 고객들과 잡담을 나누는 데 능숙해요.', 'Making small talk in a second language can feel surprisingly demanding.', '제2외국어로 잡담을 나누는 일은 의외로 부담스러울 수 있어요.', 'C1', 'greeting', 2, 'networking event'),
('col_greeting_C1_03', 'extend', 'welcome', 'extend a welcome', '환영을 표하다', 'give', '공식적이고 따뜻한 환영의 뜻을 전한다는 격식 표현이에요. 행사 개회사에서 표준이에요.', 'On behalf of the board, I would like to extend a warm welcome to our guests.', '이사회를 대표해 손님 여러분께 따뜻한 환영을 표하고 싶어요.', 'The mayor extended a welcome to the visiting delegation.', '시장은 방문단에게 환영을 표했어요.', 'C1', 'greeting', 2, 'welcome ceremony'),
('col_greeting_C1_04', 'introduce', 'yourself', 'introduce yourself', '자기소개를 하다', 'tell', '이름과 소속을 격식 있게 밝힌다는 표현이에요. 면접, 회의, 워크숍에서 표준이에요.', 'Please introduce yourself briefly so the panel can get to know you.', '심사위원단이 알 수 있도록 자기소개를 간단히 해 주세요.', 'She introduced herself as the new head of research.', '그녀는 신임 연구 책임자로 자기소개를 했어요.', 'C1', 'greeting', 2, 'introduction badge'),
('col_greeting_C1_05', 'shake', 'hands', 'shake hands', '악수하다', 'do', '인사로 손을 맞잡는다는 표준 표현이에요. ''do handshake'' 같은 표현은 어색하니 ''shake hands''로 기억하세요.', 'It is customary to shake hands firmly during a business introduction.', '비즈니스 자리에서 자기소개를 할 때는 손을 단단히 잡고 악수하는 게 관례예요.', 'They shook hands warmly after signing the agreement.', '그들은 합의서에 서명한 뒤 따뜻하게 악수했어요.', 'C1', 'greeting', 2, 'handshake business')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_greeting_C1_01', 'speak of the devil', '호랑이도 제 말하면 온다', '악마의 이야기를 하다', '방금 화제에 올린 사람이 우연히 나타났을 때 쓰는 표현이에요. 비격식이지만 직장에서도 자연스럽게 통해요.', 'Speak of the devil — I was just telling them about your new project.', '호랑이도 제 말하면 온다더니, 마침 새 프로젝트 얘기를 하고 있었어요.', 'Speak of the devil, here she comes now.', '호랑이도 제 말하면 온다더니, 마침 그녀가 오네요.', 'Well, speak of the devil, look who just joined the call.', '호랑이도 제 말하면 온다더니, 통화에 누가 들어왔는지 보세요.', 'C1', 'greeting', 2, 'surprise meeting', 1),
('idm_greeting_C1_02', 'long time no see', '오랜만이에요', '오랜 시간 보지 못함', '오랜만에 만난 사람에게 반갑게 건네는 표현이에요. 일상과 비즈니스 자리 모두에서 자연스럽게 써요.', 'Long time no see — how have you been since the conference?', '오랜만이에요. 학회 이후로 어떻게 지내셨어요?', 'Long time no see! You have not changed a bit.', '오랜만이에요! 하나도 안 변하셨네요.', 'Long time no see — last time was the Tokyo office, I believe.', '오랜만이에요. 마지막으로 뵌 게 도쿄 사무소였던 것 같아요.', 'C1', 'greeting', 2, 'reunion hug', 2),
('idm_greeting_C1_03', 'what brings you here', '여긴 어쩐 일이세요', '무엇이 당신을 여기 데려왔나요', '예상치 못한 장소에서 만난 사람에게 격식 있게 묻는 표현이에요. 친근하면서도 정중한 느낌이에요.', 'What brings you here on a Tuesday afternoon?', '화요일 오후에 여긴 어쩐 일이세요?', 'I did not expect to see you at the gallery — what brings you here?', '여기 미술관에서 뵐 줄 몰랐어요. 어쩐 일이세요?', 'What brings you here all the way from Busan?', '부산에서 여기까지 어쩐 일이세요?', 'C1', 'greeting', 2, 'unexpected meeting', 3),
('idm_greeting_C1_04', 'make yourself at home', '편하게 계세요', '집에 있는 것처럼 하세요', '손님에게 편안히 있으라고 권하는 정중한 표현이에요. 가정뿐 아니라 사무실, 호텔, 워크숍 자리에서도 자연스러워요.', 'Please come in and make yourself at home — the others will arrive shortly.', '들어오셔서 편하게 계세요. 다른 분들도 곧 오실 거예요.', 'Help yourself to tea and make yourself at home.', '차 드시고 편하게 계세요.', 'Welcome to the team — make yourself at home in the lounge.', '팀에 오신 걸 환영해요. 라운지에서 편하게 계세요.', 'C1', 'greeting', 2, 'cozy living room', 4),
('idm_greeting_C1_05', 'nice to put a face to the name', '실제로 뵙게 되어 반가워요', '이름에 얼굴을 붙여서 좋아요', '이메일이나 전화로만 알던 사람을 처음 직접 만났을 때 쓰는 격식 표현이에요. 비즈니스 자리에서 매우 자연스러워요.', 'Nice to finally put a face to the name after all those emails.', '그동안 이메일만 주고받다가 드디어 실제로 뵙게 되어 반가워요.', 'It is great to put a face to the name — your reputation precedes you.', '실제로 뵙게 되어 정말 반가워요. 명성은 익히 들었어요.', 'After two years of calls, it is wonderful to put a face to the name.', '2년간 통화만 하다가 직접 뵙게 되어 정말 좋아요.', 'C1', 'greeting', 2, 'business introduction', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_academic_C1_01', 'conduct', 'research', 'conduct research', '연구를 수행하다', 'do', '학술적 맥락에서는 ''do research''보다 ''conduct research''가 표준이에요. 논문, 보고서, 학회 발표에서 자주 써요.', 'Her team conducted research on bilingual cognition over five years.', '그녀의 팀은 5년에 걸쳐 이중 언어 인지에 관한 연구를 수행했어요.', 'The institute conducts research into renewable energy policy.', '그 연구소는 재생에너지 정책에 관한 연구를 수행해요.', 'C1', 'academic', 2, 'research laboratory'),
('col_academic_C1_02', 'publish', 'findings', 'publish findings', '연구 결과를 발표하다', 'show', '연구 결과를 학술지나 보고서 형태로 공식 공개한다는 표현이에요. 학계의 핵심 동사예요.', 'The professor published her findings in a peer-reviewed journal last month.', '그 교수는 지난달 동료 심사 저널에 자신의 연구 결과를 발표했어요.', 'They plan to publish their findings at the international conference.', '그들은 국제 학회에서 연구 결과를 발표할 계획이에요.', 'C1', 'academic', 2, 'academic journal'),
('col_academic_C1_03', 'review', 'literature', 'review the literature', '선행 연구를 검토하다', 'read', '논문 작성 초기에 관련 선행 연구를 체계적으로 살펴본다는 학술적 표현이에요. ''literature review''라는 명사형도 자주 써요.', 'Before formulating her hypothesis, she reviewed the literature thoroughly.', '가설을 세우기 전에 그녀는 선행 연구를 철저히 검토했어요.', 'Doctoral candidates must review the literature in their field extensively.', '박사 과정 학생들은 자신의 분야에서 선행 연구를 폭넓게 검토해야 해요.', 'C1', 'academic', 2, 'library bookshelves'),
('col_academic_C1_04', 'test', 'hypotheses', 'test hypotheses', '가설을 검증하다', 'try', '가설이 맞는지 실험이나 데이터 분석으로 확인한다는 과학적 표현이에요. ''hypothesis''의 복수형은 ''hypotheses''예요.', 'The experiment was designed to test several competing hypotheses.', '그 실험은 경쟁하는 여러 가설들을 검증하기 위해 설계됐어요.', 'Researchers test hypotheses using rigorous statistical methods.', '연구자들은 엄격한 통계 방법을 사용해 가설을 검증해요.', 'C1', 'academic', 2, 'scientific experiment'),
('col_academic_C1_05', 'draw', 'conclusions', 'draw conclusions', '결론을 도출하다', 'make', '데이터나 증거를 바탕으로 결론에 이른다는 학술적 표현이에요. ''make a conclusion''은 자연스럽지 않아요.', 'It is premature to draw conclusions from such a small sample size.', '이렇게 작은 표본에서 결론을 도출하기에는 시기상조예요.', 'The author draws compelling conclusions from the data.', '저자는 데이터로부터 설득력 있는 결론을 도출해요.', 'C1', 'academic', 2, 'data analysis chart')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_academic_C1_01', 'back to the drawing board', '처음부터 다시 시작하다', '제도판으로 돌아가다', '계획이나 시도가 실패해서 처음부터 다시 설계해야 할 때 써요. 연구나 프로젝트 회의에서 자주 등장해요.', 'The initial model failed peer review, so it''s back to the drawing board.', '초기 모델이 동료 심사를 통과하지 못해서, 처음부터 다시 시작해야 해요.', 'After the experiment yielded no significant results, the team went back to the drawing board.', '실험에서 유의미한 결과가 나오지 않자, 팀은 처음부터 다시 시작했어요.', 'If this approach doesn''t work, it''s back to the drawing board.', '이 접근이 안 통하면, 다시 처음부터 시작해야 해요.', 'C1', 'academic', 2, 'drawing board sketch', 1),
('idm_academic_C1_02', 'a labour of love', '애정으로 하는 일', '사랑의 노동', '돈이나 보상보다는 순수한 열정과 애정으로 하는 일을 뜻해요. 장기 연구나 저술 작업을 묘사할 때 잘 어울려요.', 'Her ten-year ethnographic study was truly a labour of love.', '그녀의 10년에 걸친 민족지 연구는 진정 애정으로 한 일이었어요.', 'Writing this monograph has been a labour of love for the professor.', '이 단행본을 쓰는 일은 그 교수에게 애정으로 하는 일이었어요.', 'The dictionary project was a labour of love spanning three decades.', '그 사전 프로젝트는 30년에 걸친 애정의 결실이었어요.', 'C1', 'academic', 2, 'researcher writing', 2),
('idm_academic_C1_03', 'the proof of the pudding', '결과가 말해준다', '푸딩의 증거', '''the proof of the pudding is in the eating''의 축약형으로, 이론보다 실제 결과가 중요하다는 뜻이에요. 학술 발표에서 응용 가능성을 논할 때 써요.', 'The theory is elegant, but the proof of the pudding is in real-world application.', '이론은 우아하지만, 결국 실제 적용 결과가 말해줘요.', 'Reviewers will judge the model on accuracy — the proof of the pudding.', '심사자들은 정확도로 모델을 평가할 거예요. 결과가 말해주죠.', NULL, NULL, 'C1', 'academic', 2, 'pudding dessert', 3),
('idm_academic_C1_04', 'armchair scholar', '탁상공론 학자', '안락의자 학자', '직접 현장 연구나 실험 없이 책상에서만 이론을 펴는 사람을 비판적으로 부르는 표현이에요. 학계 토론에서 신중히 써야 해요.', 'Critics dismissed him as an armchair scholar with no fieldwork experience.', '비평가들은 그를 현장 경험 없는 탁상공론 학자로 치부했어요.', 'Don''t be an armchair scholar — go and collect the data yourself.', '탁상공론 학자가 되지 마세요. 직접 가서 데이터를 모으세요.', 'Her work distinguishes her from the armchair scholars of the discipline.', '그녀의 연구는 그녀를 이 분야의 탁상공론 학자들과 구별 짓게 해요.', 'C1', 'academic', 2, 'armchair library', 4),
('idm_academic_C1_05', 'in the same boat', '같은 처지에 있다', '같은 배에 있다', '같은 어려움이나 상황을 공유한다는 뜻이에요. 대학원생들이 논문 압박을 이야기할 때처럼 격식 있는 자리에서도 자연스러워요.', 'All doctoral candidates are in the same boat when it comes to thesis pressure.', '논문 압박에 관해서는 모든 박사 과정 학생들이 같은 처지예요.', 'We''re all in the same boat with the funding cuts this year.', '올해 연구비 삭감에 관해서는 우리 모두 같은 처지예요.', 'Junior faculty are in the same boat regarding tenure requirements.', '신임 교수들은 종신직 요건에 관해 같은 처지에 있어요.', 'C1', 'academic', 2, 'rowing boat', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_discussion_C1_01', 'raise', 'point', 'raise a point', '의견을 제기하다', 'say', '회의나 토론에서 새로운 논점을 정중하게 꺼낼 때 써요. ''say a point''는 자연스럽지 않아요.', 'May I raise a point about the proposed timeline?', '제안된 일정에 관해 한 가지 의견을 제기해도 될까요?', 'She raised an important point about ethical considerations.', '그녀는 윤리적 고려사항에 관한 중요한 의견을 제기했어요.', 'C1', 'discussion', 2, 'meeting discussion'),
('col_discussion_C1_02', 'build', 'consensus', 'build consensus', '합의를 형성하다', 'make', '여러 사람의 의견을 모아 동의를 끌어낸다는 격식 표현이에요. 정책, 회의, 협의 맥락에서 자주 써요.', 'The chair worked hard to build consensus among committee members.', '의장은 위원들 사이의 합의를 형성하기 위해 열심히 노력했어요.', 'Building consensus takes time but produces lasting decisions.', '합의를 형성하는 데는 시간이 걸리지만 지속 가능한 결정을 낳아요.', 'C1', 'discussion', 2, 'roundtable meeting'),
('col_discussion_C1_03', 'voice', 'opinion', 'voice an opinion', '의견을 표명하다', 'tell', '자신의 의견을 공개적으로 분명하게 표현한다는 격식 표현이에요. ''give an opinion''보다 더 적극적인 뉘앙스예요.', 'Everyone was encouraged to voice their opinion during the open forum.', '공개 토론에서 모두가 의견을 표명하도록 권장됐어요.', 'She voiced a dissenting opinion at the board meeting.', '그녀는 이사회에서 반대 의견을 표명했어요.', 'C1', 'discussion', 2, 'public speaker'),
('col_discussion_C1_04', 'address', 'concerns', 'address concerns', '우려 사항을 다루다', 'answer', '제기된 걱정거리를 진지하게 검토하고 대응한다는 표현이에요. 비즈니스, 정치, 학술 토론의 표준 어휘예요.', 'The CEO took time to address employees'' concerns about restructuring.', 'CEO는 구조조정에 대한 직원들의 우려를 다루는 데 시간을 들였어요.', 'Please address any concerns before we proceed with the vote.', '투표를 진행하기 전에 우려 사항이 있으면 다뤄 주세요.', 'C1', 'discussion', 2, 'town hall meeting'),
('col_discussion_C1_05', 'weigh', 'options', 'weigh the options', '선택지를 저울질하다', 'think', '여러 가능성의 장단점을 신중히 비교 검토한다는 표현이에요. 의사결정 회의에서 자주 써요.', 'The committee weighed the options carefully before announcing its decision.', '위원회는 결정을 발표하기 전에 선택지를 신중히 저울질했어요.', 'We need to weigh the options before committing resources.', '자원을 투입하기 전에 선택지를 저울질해야 해요.', 'C1', 'discussion', 2, 'balance scale')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_discussion_C1_01', 'see eye to eye', '의견이 일치하다', '눈과 눈을 마주 보다', '두 사람이나 집단이 같은 의견을 가진다는 뜻이에요. 보통 ''not see eye to eye'' 형태로 의견 차이를 표현할 때도 자주 써요.', 'The two directors don''t always see eye to eye on strategy.', '두 이사가 전략 면에서 항상 의견이 일치하는 건 아니에요.', 'We see eye to eye on the broader vision, even if details differ.', '세부 사항은 다를지언정 우리는 큰 비전에 관해서는 의견이 일치해요.', 'It took hours, but they finally saw eye to eye.', '몇 시간 걸렸지만 결국 그들은 의견 일치를 봤어요.', 'C1', 'discussion', 2, 'two people talking', 1),
('idm_discussion_C1_02', 'agree to disagree', '서로의 견해 차이를 인정하다', '의견 불일치에 동의하다', '서로 합의에 이르지 못해도 상대의 입장을 존중하며 논쟁을 마무리한다는 표현이에요. 외교적이고 성숙한 톤이에요.', 'After two hours of debate, we agreed to disagree on the policy.', '두 시간의 토론 끝에 우리는 그 정책에 관해 견해 차이를 인정하기로 했어요.', 'On this matter, the panelists ultimately agreed to disagree.', '이 사안에 관해 패널들은 결국 서로의 견해 차이를 인정했어요.', 'Let''s agree to disagree and move on to the next item.', '서로의 견해 차이를 인정하고 다음 안건으로 넘어갑시다.', 'C1', 'discussion', 2, 'handshake disagreement', 2),
('idm_discussion_C1_03', 'common ground', '공통점', '공통의 땅', '의견이 다른 양측이 동의할 수 있는 지점을 뜻해요. 토론, 협상, 외교에서 핵심 표현이에요.', 'The mediator helped both sides find common ground.', '중재자는 양측이 공통점을 찾도록 도왔어요.', 'Despite our differences, we share common ground on sustainability.', '차이에도 불구하고 우리는 지속 가능성에 관해 공통점을 가지고 있어요.', 'Finding common ground is the first step toward resolution.', '공통점을 찾는 것이 해결을 향한 첫걸음이에요.', 'C1', 'discussion', 2, 'overlapping circles', 3),
('idm_discussion_C1_04', 'play devil''s advocate', '일부러 반대 입장을 취하다', '악마의 변호인 역할을 하다', '논의를 깊이 있게 하기 위해 자신의 진짜 입장과 무관하게 반대 의견을 펴는 것을 뜻해요. 학술 토론과 비즈니스 회의에서 자주 써요.', 'Let me play devil''s advocate for a moment and challenge that assumption.', '잠시 일부러 반대 입장을 취해서 그 전제에 이의를 제기해 볼게요.', 'A good seminar leader will play devil''s advocate to sharpen the debate.', '훌륭한 세미나 진행자는 토론을 날카롭게 하기 위해 일부러 반대 입장을 취해요.', 'I''m playing devil''s advocate here, but have you considered the downside?', '일부러 반대 입장을 취하는 거지만, 단점은 고려해 보셨나요?', 'C1', 'discussion', 2, 'debate stage', 4),
('idm_discussion_C1_05', 'hit a brick wall', '난관에 부딪히다', '벽돌 벽에 부딪치다', '논의나 협상이 진전 없이 막혔다는 뜻이에요. 격식 있는 자리에서도 자연스럽게 써요.', 'Negotiations hit a brick wall over the compensation clause.', '협상이 보상 조항에서 난관에 부딪혔어요.', 'Every time we raise that topic, we hit a brick wall.', '그 주제를 꺼낼 때마다 난관에 부딪혀요.', 'The committee hit a brick wall and adjourned the meeting.', '위원회는 난관에 부딪혀 회의를 휴회했어요.', 'C1', 'discussion', 2, 'brick wall barrier', 5)
INSERT INTO collocations (id, verb, noun, en, ko, wrong_verb, tip, ex1, ex1_ko, ex2, ex2_ko, cefr, topic_id, priority, image_keyword) VALUES
('col_negotiation_C1_01', 'reach', 'agreement', 'reach an agreement', '합의에 이르다', 'make', '협상 끝에 양측이 동의에 이른다는 표준 표현이에요. ''make an agreement''보다 협상 과정의 결실이라는 뉘앙스가 강해요.', 'After months of talks, the two parties finally reached an agreement.', '몇 달간의 협상 끝에 양측은 마침내 합의에 이르렀어요.', 'We hope to reach an agreement by the end of the quarter.', '분기 말까지 합의에 이르기를 바라요.', 'C1', 'negotiation', 2, 'business handshake'),
('col_negotiation_C1_02', 'make', 'concession', 'make a concession', '양보를 하다', 'give', '협상에서 자신의 요구를 일부 포기한다는 격식 표현이에요. 외교, 노사 협상, 비즈니스 딜에서 자주 써요.', 'Both sides will need to make concessions to close this deal.', '이 딜을 성사시키려면 양측이 양보를 해야 할 거예요.', 'The union made a significant concession on overtime pay.', '노조는 초과근무 수당에 관해 중요한 양보를 했어요.', 'C1', 'negotiation', 2, 'negotiation handshake'),
('col_negotiation_C1_03', 'set', 'terms', 'set the terms', '조건을 정하다', 'put', '계약이나 협상의 조건을 정한다는 표현이에요. 누가 ''set the terms''하는지가 협상력의 핵심이에요.', 'The acquiring company sought to set the terms of the merger.', '인수 회사는 합병 조건을 정하려 했어요.', 'Whoever sets the terms first often shapes the deal.', '먼저 조건을 정하는 쪽이 종종 딜의 형태를 결정해요.', 'C1', 'negotiation', 2, 'contract terms'),
('col_negotiation_C1_04', 'walk', 'away', 'walk away from', '협상을 결렬시키다', 'leave', '협상이 자신에게 불리할 때 그만두고 나간다는 표현이에요. ''walk away from the table''로도 자주 써요.', 'They were prepared to walk away from the deal if their terms weren''t met.', '그들은 조건이 받아들여지지 않으면 딜을 결렬시킬 준비가 돼 있었어요.', 'Sometimes the best negotiation tactic is being willing to walk away.', '때로는 결렬시킬 의향을 보이는 게 최고의 협상 전술이에요.', 'C1', 'negotiation', 2, 'businessperson leaving'),
('col_negotiation_C1_05', 'drive', 'bargain', 'drive a hard bargain', '강하게 흥정하다', 'do', '협상에서 자신에게 유리한 조건을 단호하게 끌어낸다는 표현이에요. 보통 ''drive a hard bargain'' 형태로 써요.', 'She drives a hard bargain — expect lengthy negotiations.', '그녀는 강하게 흥정하니까, 긴 협상을 예상하세요.', 'The supplier drove a hard bargain on bulk pricing.', '공급업체는 대량 가격에서 강하게 흥정했어요.', 'C1', 'negotiation', 2, 'business bargaining')
INSERT INTO idioms (id, en, ko, literal_ko, tip, ex1, ex1_ko, ex2, ex2_ko, ex3, ex3_ko, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('idm_negotiation_C1_01', 'meet halfway', '서로 양보해 타협하다', '중간 지점에서 만나다', '양측이 각자 양보해서 중간 지점에서 합의한다는 뜻이에요. 협상이나 갈등 해결의 핵심 표현이에요.', 'If you can lower the price, we''ll meet you halfway on the delivery terms.', '가격을 낮춰 주시면 배송 조건에서 저희가 절반 양보할게요.', 'Let''s meet halfway and split the additional costs.', '서로 양보해서 추가 비용을 반반 부담합시다.', 'A good negotiator knows when to meet the other side halfway.', '훌륭한 협상가는 언제 상대와 타협할지 알아요.', 'C1', 'negotiation', 2, 'middle ground meeting', 1),
('idm_negotiation_C1_02', 'deal breaker', '협상 결렬 요인', '딜을 깨는 것', '협상에서 절대 받아들일 수 없어 딜 자체를 무산시키는 조건을 뜻해요. 비즈니스 협상의 핵심 어휘예요.', 'Non-compete clauses are a deal breaker for many senior executives.', '경업 금지 조항은 많은 임원들에게 협상 결렬 요인이에요.', 'For us, that pricing structure is a deal breaker.', '저희에게 그 가격 구조는 협상 결렬 요인이에요.', 'They identified three potential deal breakers early in the talks.', '그들은 협상 초기에 세 가지 잠재적 결렬 요인을 식별했어요.', 'C1', 'negotiation', 2, 'contract negotiation', 2),
('idm_negotiation_C1_03', 'have the upper hand', '우위를 점하다', '윗손을 가지다', '협상이나 경쟁에서 더 유리한 위치에 있다는 뜻이에요. 비즈니스, 정치, 스포츠 등에서 두루 써요.', 'With multiple offers on the table, she had the upper hand in salary talks.', '여러 제안이 들어와 있어서 그녀는 연봉 협상에서 우위를 점했어요.', 'Market conditions gave the buyer the upper hand this quarter.', '시장 상황이 이번 분기 구매자에게 우위를 줬어요.', 'They held the upper hand until competitors entered the market.', '경쟁사들이 시장에 진입할 때까지 그들은 우위를 점하고 있었어요.', 'C1', 'negotiation', 2, 'chess strategy', 3),
('idm_negotiation_C1_04', 'common ground', '공통의 입장', '공통의 땅', '협상에서 양측이 동의할 수 있는 지점을 뜻해요. 외교와 비즈니스 협상의 핵심 개념이에요.', 'The mediator helped the two parties find common ground on key issues.', '중재자는 양측이 주요 사안에서 공통의 입장을 찾도록 도왔어요.', 'There''s common ground here — let''s build on it.', '여기 공통의 입장이 있어요. 이를 바탕으로 발전시킵시다.', 'Even rival firms can find common ground on industry standards.', '경쟁 기업들도 업계 표준에 관해서는 공통의 입장을 찾을 수 있어요.', 'C1', 'negotiation', 2, 'overlapping circles', 4),
('idm_negotiation_C1_05', 'back to square one', '원점으로 돌아가다', '1번 칸으로 돌아가다', '진전이 무산되어 처음부터 다시 시작해야 한다는 뜻이에요. 협상이 결렬되거나 진척이 사라졌을 때 써요.', 'The contract fell through, so we''re back to square one.', '계약이 무산돼서 우리는 원점으로 돌아갔어요.', 'If they reject this offer, we''re back to square one.', '그들이 이 제안을 거절하면 원점으로 돌아가요.', 'After six months of talks, the talks collapsed and they were back to square one.', '6개월간의 협상 끝에 회담이 결렬되어 그들은 원점으로 돌아갔어요.', 'C1', 'negotiation', 2, 'board game square', 5)
